import React, { useState } from 'react';
import { Region, RegionType, ClanMember, RegionCategory } from '../types';

interface Props {
    regions: Region[];
    members: ClanMember[];
    onSelectRegion: (region: Region | null) => void;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onUpdateRegion: (id: string, updates: Partial<Region>) => void;
    currentRegionId: string;
}

const WorldMap: React.FC<Props> = ({ regions, members, onSelectRegion, onUpdateMember, onUpdateRegion, currentRegionId }) => {
    const [hoveredRegionId, setHoveredRegionId] = useState<string | null>(null);

    const selectedRegion = regions.find(r => r.id === currentRegionId);
    const idleMembers = members.filter(m => m.status === 'healthy' && (m.assignment === 'Idle' || m.assignment === 'Patrol'));
    const hoveredRegion = regions.find(r => r.id === hoveredRegionId);

    const getTypeIcon = (type: RegionType, category: RegionCategory) => {
        if (category === 'Mystic') return '✨';
        switch (type) {
            case 'lake': return '🌊';
            case 'mountain': return '⛰️';
            case 'forest': return '🌿';
            case 'city': return '🏮';
            case 'sect': return '⛩️';
            case 'ruins': return '🏺';
            case 'cave': return '🕳️';
            default: return '📍';
        }
    };

    const getCategoryLabel = (category: RegionCategory) => {
        switch (category) {
            case 'Natural': return '自然资源点';
            case 'Stakeholder': return '势力聚居地';
            case 'Mystic': return '上古秘境';
        }
    };

    const handleDispatch = (memberId: string, region: Region) => {
        let turns = 1;
        if (region.category === 'Natural') turns = 1 + Math.floor(region.difficulty / 3);
        if (region.category === 'Mystic') turns = 3 + Math.floor(region.difficulty / 2);

        onUpdateMember(memberId, { assignment: 'Mission' });
        onUpdateRegion(region.id, {
            activeMission: {
                memberId,
                turnsRemaining: turns,
                totalTurns: turns
            }
        });
    };

    // 智能计算面板位置，防止超出边界
    const panelSide = selectedRegion ? (selectedRegion.x > 60 ? 'left' : 'right') : 'right';
    // 垂直修正：如果点太靠上或靠下，调整 translate
    const translateY = selectedRegion ? (selectedRegion.y < 30 ? '0%' : selectedRegion.y > 70 ? '-100%' : '-50%') : '-50%';
    const verticalOffset = selectedRegion ? (selectedRegion.y < 30 ? '20px' : selectedRegion.y > 70 ? '-20px' : '0px') : '0px';

    return (
        <div className="relative w-full h-full parchment scroll-shadow overflow-hidden border-8 border-[#4a3728]">
            <div className="absolute top-4 left-1/2 -translate-x-1/2 text-5xl font-cursive opacity-10 select-none pointer-events-none">
                天罡大陆 · 望月湖畔
            </div>

            <div className="absolute inset-0 pointer-events-none">
                <svg width="100%" height="100%" className="opacity-10">
                    <path d="M50,150 C150,100 250,200 450,150 S650,50 850,250" stroke="#2c1810" fill="none" strokeWidth="1" strokeDasharray="5,5" />
                    <path d="M100,500 Q300,400 500,550 T900,450" stroke="#2c1810" fill="none" strokeWidth="2" opacity="0.4" />
                </svg>
            </div>

            {regions.map(region => {
                if (!region.isDiscovered) {
                    return (
                        <div 
                            key={region.id}
                            className="absolute transform -translate-x-1/2 -translate-y-1/2 opacity-20 pointer-events-none"
                            style={{ left: `${region.x}%`, top: `${region.y}%` }}
                        >
                            <div className="w-8 h-8 flex items-center justify-center bg-black/10 rounded-full text-lg grayscale blur-[0.5px]">
                                ❔
                            </div>
                        </div>
                    );
                }

                const isOccupied = !!region.activeMission;

                return (
                    <button
                        key={region.id}
                        onClick={() => onSelectRegion(region)}
                        onMouseEnter={() => setHoveredRegionId(region.id)}
                        onMouseLeave={() => setHoveredRegionId(null)}
                        className={`absolute transform -translate-x-1/2 -translate-y-1/2 transition-all duration-500 group
                            ${currentRegionId === region.id ? 'scale-125 z-20' : 'hover:scale-110'}`}
                        style={{ left: `${region.x}%`, top: `${region.y}%` }}
                    >
                        <div className="flex flex-col items-center">
                            <div className={`w-10 h-10 flex items-center justify-center rounded-full border-2 relative
                                ${currentRegionId === region.id ? 'bg-red-900 border-yellow-400 shadow-[0_0_15px_rgba(234,179,8,0.5)]' : 'bg-[#4a3728] border-[#2c1810]'} 
                                text-xl shadow-lg transition-colors`}>
                                {getTypeIcon(region.type, region.category)}

                                {isOccupied && (
                                    <div className="absolute -top-2 -right-2 w-5 h-5 bg-orange-600 rounded-full border border-white text-[10px] flex items-center justify-center animate-bounce text-white">
                                        ⏳
                                    </div>
                                )}
                            </div>
                            <div className="mt-1">
                                <span className={`text-[9px] font-bold bg-[#f4e4bc]/95 px-1.5 py-0.5 rounded border border-[#4a3728] whitespace-nowrap shadow-sm
                                    ${currentRegionId === region.id ? 'text-red-900 border-red-900 ring-1 ring-red-400' : 'text-[#2c1810]'}`}>
                                    {region.name}
                                </span>
                            </div>
                        </div>
                    </button>
                );
            })}

            {hoveredRegion && hoveredRegionId !== currentRegionId && (
                <div 
                    className="absolute z-50 pointer-events-none bg-black/90 text-white p-2 rounded shadow-xl border border-yellow-900/50 min-w-[120px]"
                    style={{ left: `${hoveredRegion.x}%`, top: `${hoveredRegion.y - 8}%`, transform: 'translateX(-50%)' }}
                >
                    <p className="text-xs font-bold text-yellow-500">{hoveredRegion.name}</p>
                    <p className="text-[10px] opacity-70">{getCategoryLabel(hoveredRegion.category)}</p>
                    <p className="text-[9px] mt-1 text-red-400">难度: {hoveredRegion.difficulty}</p>
                </div>
            )}

            {selectedRegion && selectedRegion.isDiscovered && (
                <div 
                    className={`absolute z-30 animate-scale-in flex flex-col pointer-events-auto`}
                    style={{ 
                        left: `${selectedRegion.x}%`, 
                        top: `calc(${selectedRegion.y}% + ${verticalOffset})`,
                        transform: `translate(${panelSide === 'right' ? '40px' : '-110%'}, ${translateY})`
                    }}
                >
                    <div className="w-72 sm:w-80 bg-[#1e1410] border-2 border-yellow-900/40 rounded-lg shadow-[0_20px_50px_rgba(0,0,0,0.8)] overflow-hidden flex flex-col max-h-[70vh]">
                        <div className="p-3 border-b border-yellow-900/20 bg-[#2c1810]/80 flex justify-between items-center shrink-0">
                            <div className="flex items-center gap-2">
                                <div className="text-lg">{getTypeIcon(selectedRegion.type, selectedRegion.category)}</div>
                                <div>
                                    <h3 className="text-yellow-500 font-bold text-sm">
                                        {selectedRegion.name}
                                    </h3>
                                    <p className="text-[9px] text-yellow-800 uppercase tracking-widest font-bold">
                                        {selectedRegion.owner}
                                    </p>
                                </div>
                            </div>
                            <button 
                                onClick={(e) => { e.stopPropagation(); onSelectRegion(null); }}
                                className="w-6 h-6 flex items-center justify-center rounded-full hover:bg-red-900/30 text-gray-500 hover:text-red-500 transition-colors text-lg"
                            >
                                ×
                            </button>
                        </div>

                        <div className="flex-1 overflow-y-auto p-3 space-y-3 bg-[#1e1410]/95 backdrop-blur-sm custom-scrollbar">
                            <p className="text-[11px] text-gray-400 italic leading-relaxed border-l-2 border-yellow-900/30 pl-2 py-1">
                                {selectedRegion.description}
                            </p>

                            <div className="flex flex-wrap gap-1">
                                {selectedRegion.resources.map(r => (
                                    <span key={r} className="bg-yellow-900/10 text-yellow-700 px-2 py-0.5 rounded text-[8px] border border-yellow-900/10 font-bold">
                                        • {r}
                                    </span>
                                ))}
                            </div>

                            <div className="pt-2 border-t border-yellow-900/10">
                                {selectedRegion.activeMission ? (
                                    <div className="p-4 bg-orange-900/10 rounded border border-orange-900/20 text-center space-y-2">
                                        <p className="text-xs text-orange-400 font-bold">任务执行中</p>
                                        <div className="w-full bg-black/40 h-1.5 rounded-full overflow-hidden">
                                            <div 
                                                className="h-full bg-orange-500" 
                                                style={{ width: `${(1 - selectedRegion.activeMission.turnsRemaining / selectedRegion.activeMission.totalTurns) * 100}%` }}
                                            ></div>
                                        </div>
                                        <p className="text-[10px] text-gray-500">剩余 {selectedRegion.activeMission.turnsRemaining} 年</p>
                                    </div>
                                ) : (
                                    <>
                                        {selectedRegion.category !== 'Stakeholder' ? (
                                            <>
                                                <h4 className="text-[10px] text-yellow-600 font-bold uppercase mb-2 flex justify-between">
                                                    <span>派遣族人</span>
                                                    <span className="text-gray-600">空闲: {idleMembers.length}</span>
                                                </h4>

                                                <div className="space-y-1">
                                                    {idleMembers.length > 0 ? (
                                                        idleMembers.map(member => (
                                                            <div key={member.id} className="bg-black/30 border border-yellow-900/5 hover:border-yellow-700/30 rounded p-2 flex justify-between items-center transition-all group">
                                                                <div className="flex flex-col">
                                                                    <span className="text-xs text-yellow-100 group-hover:text-yellow-500">{member.name}</span>
                                                                    <span className="text-[9px] text-gray-500 font-sans">{member.realm}{member.subRealm}层</span>
                                                                </div>
                                                                <button 
                                                                    onClick={() => handleDispatch(member.id, selectedRegion)}
                                                                    className="px-2 py-1 bg-yellow-900/20 hover:bg-yellow-700 text-yellow-600 hover:text-white text-[9px] rounded border border-yellow-900/30 transition-all font-bold"
                                                                >
                                                                    派遣
                                                                </button>
                                                            </div>
                                                        ))
                                                    ) : (
                                                        <p className="text-center py-2 text-[10px] text-gray-700 italic">当前无闲置族人</p>
                                                    )}
                                                </div>
                                            </>
                                        ) : (
                                            <div className="p-4 bg-blue-900/10 rounded border border-blue-900/20 text-center">
                                                <p className="text-xs text-blue-400">势力范围，暂无常驻任务</p>
                                            </div>
                                        )}
                                    </>
                                )}
                            </div>
                        </div>

                        <div className="p-1.5 bg-black/60 text-center border-t border-yellow-900/10 shrink-0">
                            <p className="text-[8px] text-gray-600 uppercase">
                                {getCategoryLabel(selectedRegion.category)} · 难 {selectedRegion.difficulty}
                            </p>
                        </div>
                    </div>
                </div>
            )}

            <style>{`
                @keyframes scale-in {
                    from { opacity: 0; scale: 0.95; }
                    to { opacity: 1; scale: 1; }
                }
                .animate-scale-in {
                    animation: scale-in 0.2s cubic-bezier(0.16, 1, 0.3, 1) forwards;
                }
                .custom-scrollbar::-webkit-scrollbar { width: 3px; }
                .custom-scrollbar::-webkit-scrollbar-thumb { background: #3d2b24; border-radius: 10px; }
            `}</style>
        </div>
    );
};

export default WorldMap;

import React, { useState, useMemo } from 'react';
import { GameState, ClanMember, Realm, TaskType, DevelopmentPlan, MethodTier, CultivationMethod, MethodType } from '../types';
import { TASK_INFO, REALM_ORDER, DEVELOPMENT_PLANS, CULTIVATION_METHODS, POSITIONS } from '../constants';

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddMember: () => void;
}

const ITEMS_PER_PAGE = 8;

const ClanDashboard: React.FC<Props> = ({ state, onUpdateMember, onAddMember }) => {
    const [selectedMemberId, setSelectedMemberId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'alive' | 'deceased'>('alive');
    const [currentPage, setCurrentPage] = useState(0);
    const [detailTab, setDetailTab] = useState<'attr' | 'talents' | 'tasks' | 'cultivation' | 'plan' | 'position'>('attr');

    const [focusedSlot, setFocusedSlot] = useState<string | null>(null);
    const [focusedLibraryMethodId, setFocusedLibraryMethodId] = useState<string | null>(null);

    const selectedMember = useMemo(() => 
        state.members.find(m => m.id === selectedMemberId), 
    [state.members, selectedMemberId]);

    const [libraryType, setLibraryType] = useState<MethodType>('Cultivation');

    const filteredMembers = useMemo(() => {
        const list = state.members.filter(m => activeTab === 'alive' ? m.status !== 'dead' : m.status === 'dead');
        return list.sort((a, b) => {
            if (activeTab === 'alive') {
                const realmDiff = REALM_ORDER.indexOf(b.realm) - REALM_ORDER.indexOf(a.realm);
                if (realmDiff !== 0) return realmDiff;
                return b.subRealm - a.subRealm;
            }
            return (b.deathYear || 0) - (a.deathYear || 0);
        });
    }, [state.members, activeTab]);

    const pagedMembers = filteredMembers.slice(currentPage * ITEMS_PER_PAGE, (currentPage + 1) * ITEMS_PER_PAGE);

    const handleTabChange = (tab: 'alive' | 'deceased') => {
        setActiveTab(tab);
        setCurrentPage(0);
        setSelectedMemberId(null);
    };

    const getTierColor = (tier: MethodTier) => {
        switch (tier) {
            case '低等': return 'border-gray-100 text-gray-100 bg-gray-500/10 shadow-[0_0_5px_rgba(255,255,255,0.2)]';
            case '中等': return 'border-blue-400 text-blue-400 bg-blue-500/10 shadow-[0_0_8px_rgba(59,130,246,0.3)]';
            case '高等': return 'border-purple-500 text-purple-400 bg-purple-500/10 shadow-[0_0_10px_rgba(168,85,247,0.4)]';
            case '绝世': return 'border-red-600 text-red-500 bg-red-600/10 shadow-[0_0_15px_rgba(239,68,68,0.5)]';
            default: return 'border-gray-500 text-gray-400';
        }
    };

    const toggleMethod = (methodId: string, type: MethodType) => {
        if (!selectedMember) return;

        if (type === 'Cultivation') {
            onUpdateMember(selectedMember.id, { mainMethodId: selectedMember.mainMethodId === methodId ? null : methodId });
        } else if (type === 'Movement') {
            onUpdateMember(selectedMember.id, { movementMethodId: selectedMember.movementMethodId === methodId ? null : methodId });
        } else if (type === 'Combat') {
            const currentAux = selectedMember.auxMethodIds;
            if (currentAux.includes(methodId)) {
                onUpdateMember(selectedMember.id, { auxMethodIds: currentAux.filter(mid => mid !== methodId) });
            } else if (currentAux.length < 4) {
                onUpdateMember(selectedMember.id, { auxMethodIds: [...currentAux, methodId] });
            }
        }
        setFocusedSlot(null);
        setFocusedLibraryMethodId(null);
    };

    const getElementColorClass = (key: string, val: number) => {
        if (val === 0) return 'text-gray-600 border-gray-800 opacity-30';
        switch (key) {
            case 'gold': return 'text-yellow-400 border-yellow-500 bg-yellow-500/10';
            case 'wood': return 'text-green-400 border-green-500 bg-green-500/10';
            case 'water': return 'text-blue-400 border-blue-500 bg-blue-500/10';
            case 'fire': return 'text-red-400 border-red-500 bg-red-500/10';
            case 'earth': return 'text-orange-700 border-orange-800 bg-orange-800/10';
            default: return 'text-gray-400 border-gray-500';
        }
    };

    const getElementName = (key: string) => {
        switch (key) {
            case 'gold': return '金';
            case 'wood': return '木';
            case 'water': return '水';
            case 'fire': return '火';
            case 'earth': return '土';
            default: return key;
        }
    };

    const libraryMethods = useMemo(() => {
        return CULTIVATION_METHODS.filter(m => m.type === libraryType);
    }, [libraryType]);

    const renderSlotItem = (methodId: string | null, type: MethodType, label: string, slotKey: string) => {
        const method = CULTIVATION_METHODS.find(m => m.id === methodId);
        const isFocused = focusedSlot === slotKey;

        return (
            <div className="flex flex-col items-center gap-1">
                <div 
                    onClick={() => methodId && setFocusedSlot(isFocused ? null : slotKey)}
                    className={`relative cursor-pointer transition-all duration-300 rounded flex items-center justify-center 
                        ${type === 'Cultivation' ? 'w-16 h-16 sm:w-24 sm:h-24 border-4 border-yellow-600/20' : 'w-12 h-12 sm:w-16 sm:h-16 border-2 border-yellow-900/20'} 
                        bg-black/50 overflow-hidden hover:border-yellow-500/50`}
                >
                    {method ? (
                        <div className={`w-full h-full border-2 p-1 flex flex-col items-center justify-center text-center font-bold ${getTierColor(method.tier)}`}>
                            <span className={type === 'Cultivation' ? 'text-[10px] sm:text-xs' : 'text-[7px] sm:text-[8px]'}>{method.name}</span>
                        </div>
                    ) : (
                        <div className="text-gray-800 text-[8px] sm:text-[10px] opacity-40 italic">{label}</div>
                    )}

                    {methodId && isFocused && (
                        <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center p-1 animate-fade-in z-20">
                            <button 
                                onClick={(e) => { e.stopPropagation(); toggleMethod(methodId, type); }}
                                className="bg-red-900/80 hover:bg-red-700 text-white text-[9px] sm:text-[10px] py-1 px-3 rounded-full border border-red-500/50 shadow-lg"
                            >
                                卸下
                            </button>
                        </div>
                    )}
                </div>
                <span className="text-[8px] sm:text-[10px] text-yellow-700/80 font-bold bg-black/30 px-2 sm:px-3 py-0.5 rounded-full border border-yellow-900/10">{label}</span>
            </div>
        );
    };

    return (
        <div className="bg-[#1e130c] border-l-4 border-yellow-800 h-full flex flex-col relative overflow-hidden font-serif shadow-2xl">
            <div className="p-4 border-b border-yellow-900/30 bg-black/40 shrink-0">
                <div className="flex justify-between items-center mb-4">
                    <h2 className="text-xl font-cursive text-yellow-500">⛩️ 族谱常青</h2>
                    <span className="text-[10px] text-yellow-700 bg-black/50 px-3 py-1 rounded-full border border-yellow-900/20">
                        底蕴: {state.heritagePool}
                    </span>
                </div>
                <div className="grid grid-cols-2 gap-2 mb-4">
                    <div className="bg-[#2c1810]/50 p-2 rounded border border-yellow-900/20">
                        <p className="text-[9px] text-gray-500">家族灵石</p>
                        <p className="text-yellow-400 font-bold text-sm">✨ {state.spiritStones}</p>
                    </div>
                    <div className="bg-[#2c1810]/50 p-2 rounded border border-yellow-900/20">
                        <p className="text-[9px] text-gray-500">族人数量</p>
                        <p className="text-blue-400 font-bold text-sm">👥 {state.members.filter(m => m.status !== 'dead').length}</p>
                    </div>
                </div>
                <div className="flex p-1 bg-black/40 rounded-lg gap-1 border border-yellow-900/10">
                    <button onClick={() => handleTabChange('alive')} className={`flex-1 py-1.5 text-xs rounded transition-all ${activeTab === 'alive' ? 'bg-yellow-800 text-yellow-100 shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}>在世族人</button>
                    <button onClick={() => handleTabChange('deceased')} className={`flex-1 py-1.5 text-xs rounded transition-all ${activeTab === 'deceased' ? 'bg-gray-800 text-gray-100' : 'text-gray-500 hover:text-gray-300'}`}>英灵祠堂</button>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-2 scrollbar-hide">
                {activeTab === 'alive' && (
                    <button onClick={onAddMember} className="w-full bg-green-900/20 hover:bg-green-800/40 text-green-400 border border-green-900/50 py-2 rounded text-xs transition-all flex items-center justify-center gap-2 mb-4 group">
                        <span>👶</span> 诞育麟儿
                    </button>
                )}
                {pagedMembers.length > 0 ? pagedMembers.map(member => (
                    <div 
                        key={member.id} onClick={() => activeTab === 'alive' && setSelectedMemberId(member.id)}
                        className={`group p-3 rounded-md border transition-all cursor-pointer ${selectedMemberId === member.id ? 'bg-[#2d1e15] border-yellow-600 scale-[1.02] shadow-xl' : 'bg-[#1e130c] border-yellow-900/30 hover:border-yellow-700/50'}`}
                    >
                        <div className="flex justify-between items-center mb-1">
                            <div className="flex items-center gap-2">
                                <span className="font-bold text-sm text-yellow-100/90">{member.name}</span>
                                <span className="text-[8px] text-orange-400 opacity-60">[{member.position}]</span>
                                {member.assignment === 'Cultivation' && <span className="text-[8px] animate-pulse text-blue-400">修炼中</span>}
                            </div>
                            <span className={`text-[9px] px-1.5 py-0.5 rounded-sm bg-yellow-900/40 text-yellow-500 border border-yellow-700/20`}>{member.realm}</span>
                        </div>
                        <div className="flex justify-between text-[10px] text-gray-500">
                            <span>评级: <span className="text-yellow-700 font-bold">{member.tier}</span></span>
                            <span className="text-[9px] opacity-70 italic">{member.rootGrade}</span>
                        </div>
                        {activeTab === 'alive' && (
                            <div className="mt-2 w-full h-1 bg-black/40 rounded-full overflow-hidden border border-white/5">
                                <div className="h-full bg-blue-500/60" style={{ width: `${member.cultivationProgress}%` }}></div>
                            </div>
                        )}
                    </div>
                )) : (
                    <div className="py-20 text-center text-gray-700 opacity-40 italic">空空如也</div>
                )}
            </div>

            {selectedMember && activeTab === 'alive' && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 p-2 sm:p-4 font-serif">
                    <div className="relative w-full max-w-6xl h-full sm:h-[90vh] bg-[#1a2521] border-[4px] sm:border-[12px] border-[#2c3e34] rounded-sm shadow-2xl overflow-hidden flex flex-col">
                        <div className="h-14 bg-[#141e1b] border-b border-[#2c3e34] flex items-center px-4 sm:px-8 gap-2 sm:gap-4 overflow-x-auto scrollbar-hide shrink-0">
                            <div className="flex items-center gap-1 sm:gap-2">
                                <button onClick={() => setDetailTab('attr')} className={`whitespace-nowrap px-2 sm:px-4 py-1 text-[10px] sm:text-xs transition-all border-b-2 ${detailTab === 'attr' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>👤 属性</button>
                                <button onClick={() => setDetailTab('talents')} className={`whitespace-nowrap px-2 sm:px-4 py-1 text-[10px] sm:text-xs transition-all border-b-2 ${detailTab === 'talents' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>📜 天赋</button>
                                <button onClick={() => setDetailTab('cultivation')} className={`whitespace-nowrap px-2 sm:px-4 py-1 text-[10px] sm:text-xs transition-all border-b-2 ${detailTab === 'cultivation' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>🌀 功法</button>
