                                                <p className="text-yellow-500 font-cursive text-xl lg:text-2xl [writing-mode:vertical-rl] tracking-[0.2em]">{selectedMember.name}</p>
                                            </div>
                                        </div>
                                    </div>

                                    <div className="flex-1 p-4 sm:p-6 lg:p-12 overflow-y-auto custom-scrollbar bg-[#1a2521]/50">
                                        {detailTab === 'attr' && (
                                            <div className="space-y-8 animate-fade-in">
                                                <div>
