                                                        <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">神识：</span><span className="text-blue-400 font-bold">{selectedMember.divineSense}</span></div>
                                                        <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">职位：</span><span className="text-orange-400 font-bold">{selectedMember.position}</span></div>
                                                    </div>
