                                                    <div className="w-full h-2 bg-gray-900 rounded-full overflow-hidden border border-white/10">
                                                        <div className="h-full bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.5)] transition-all" style={{ width: `${selectedMember.cultivationProgress}%` }}></div>
                                                    </div>
