                                                <div>
                                                    <h4 className="text-yellow-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-yellow-900/10 pb-2 mb-6">五行禀赋：{selectedMember.rootGrade}</h4>
                                                    <div className="grid grid-cols-5 gap-2 bg-black/30 p-4 rounded-xl">
