                                                                    <span className="text-[10px] sm:text-xs">{getElementName(key)}</span>
                                                                </div>
                                                                <span className={`text-xs font-bold ${val > 0 ? getElementColorClass(key, val).split(' ')[0] : 'text-gray-800'}`}>{val}</span>
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>
                                            </div>
                                        )}
                                        {detailTab === 'talents' && (
                                            <div className="space-y-8 animate-fade-in">
                                                <div>
                                                    <h4 className="text-red-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-red-900/10 pb-2 mb-4">⚔️ 战斗造诣</h4>
                                                    <div className="grid grid-cols-2 sm:grid-cols-5 gap-3">
                                                        {(Object.entries(selectedMember.talents.combat) as [string, number][]).map(([key, val]) => (
                                                            <div key={key} className="bg-black/20 p-2 sm:p-3 rounded-lg border border-white/5 text-center">
                                                                <p className="text-[8px] text-gray-500 uppercase">{key}</p>
                                                                <p className="text-sm font-bold text-gray-100">{Math.floor(val)}</p>
