                                                        <div className="absolute z-50 invisible group-hover:visible top-full sm:bottom-full sm:top-auto left-1/2 -translate-x-1/2 mb-2 w-40 sm:w-52 bg-black/95 border-2 border-yellow-900/50 p-2 sm:p-4 rounded-lg text-left shadow-2xl pointer-events-none">
