                            ) : (
                                <div className="flex-1 flex flex-col sm:flex-row overflow-hidden">
                                    <div className="hidden sm:flex w-1/3 flex-col items-center justify-center border-r border-[#2c3e34] p-8 bg-black/10 shrink-0">
                                        <div className="w-40 h-56 lg:w-56 lg:h-72 bg-black/40 rounded-full border-2 border-yellow-900/20 relative flex items-center justify-center">
                                            <div className="text-6xl lg:text-8xl opacity-10">🧘</div>
                                            <div className="absolute -right-4 top-1/2 -translate-y-1/2 bg-[#2c3e34] border border-yellow-900/30 px-2 py-4 rounded-md">
