                                            <div className="space-y-8 animate-fade-in">
                                                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                                    <div>
                                                        <h4 className="text-yellow-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-yellow-900/10 pb-2 mb-4">核心元气</h4>
                                                        <div className="grid grid-cols-2 gap-4 text-xs sm:text-sm">
                                                            <div className="flex justify-between border-b border-white/5 pb-2">
                                                                <span className="text-gray-500">性别：</span>
                                                                <span className="text-gray-300 font-bold">{selectedMember.gender}</span>
                                                            </div>
                                                            <div className="flex justify-between border-b border-white/5 pb-2">
                                                                <span className="text-gray-500">年龄：</span>
                                                                <span className="text-gray-300 font-bold">{selectedMember.age} 岁</span>
                                                            </div>
                                                            <div className="flex justify-between border-b border-white/5 pb-2">
                                                                <span className="text-gray-500">剩余寿元：</span>
                                                                <span className={`font-bold ${selectedMember.maxAge - selectedMember.age < 10 ? 'text-red-500 animate-pulse' : 'text-green-400'}`}>
                                                                    {selectedMember.maxAge - selectedMember.age} 载
                                                                </span>
                                                            </div>
                                                            <div className="flex justify-between border-b border-white/5 pb-2">
                                                                <span className="text-gray-500">总寿元：</span>
                                                                <span className="text-gray-300">{selectedMember.maxAge} 载</span>
                                                            </div>
                                                            <div className="flex justify-between border-b border-white/5 pb-2">
                                                                <span className="text-gray-500">宗门：</span>
                                                                <span className="text-blue-300">{selectedMember.sect}</span>
                                                            </div>
                                                            <div className="flex justify-between border-b border-white/5 pb-2">
                                                                <span className="text-gray-500">职位：</span>
                                                                <span className="text-orange-400 font-bold">{selectedMember.position}</span>
                                                            </div>
                                                        </div>
                                                    </div>
                                                    <div>
                                                        <h4 className="text-blue-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-blue-900/10 pb-2 mb-4">神魂天资</h4>
                                                        <div className="grid grid-cols-2 gap-4 text-xs sm:text-sm">
                                                            <div className="flex justify-between border-b border-white/5 pb-2">
                                                                <span className="text-gray-500">修行资质：</span>
                                                                <span className="text-yellow-500 font-bold">{selectedMember.aptitude}</span>
                                                            </div>
                                                            <div className="flex justify-between border-b border-white/5 pb-2">
                                                                <span className="text-gray-500">悟性：</span>
                                                                <span className="text-purple-400 font-bold">{selectedMember.comprehension}</span>
                                                            </div>
                                                            <div className="flex justify-between border-b border-white/5 pb-2">
                                                                <span className="text-gray-500">神识范围：</span>
                                                                <span className="text-cyan-400 font-bold">{selectedMember.divineSense}</span>
                                                            </div>
                                                            <div className="flex justify-between border-b border-white/5 pb-2">
                                                                <span className="text-gray-500">特殊体质：</span>
                                                                <span className="text-pink-500 font-bold">{selectedMember.physique}</span>
                                                            </div>
                                                            <div className="col-span-2 flex justify-between border-b border-white/5 pb-2 mt-2">
                                                                <span className="text-gray-500">当前任务：</span>
                                                                <span className={`${TASK_INFO[selectedMember.assignment].color} font-bold`}>
                                                                    {TASK_INFO[selectedMember.assignment].label}
                                                                </span>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>

                                                <div>
                                                    <h4 className="text-blue-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-blue-900/10 pb-2 mb-4">修为进度：{selectedMember.realm} {selectedMember.subRealm}层</h4>
                                                    <div className="w-full h-2 bg-gray-900 rounded-full overflow-hidden border border-white/10">
                                                        <div className="h-full bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.5)] transition-all" style={{ width: `${selectedMember.cultivationProgress}%` }}></div>
                                                    </div>
                                                </div>

                                                <div>
                                                    <h4 className="text-yellow-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-yellow-900/10 pb-2 mb-6">五行禀赋：{selectedMember.rootGrade}</h4>
                                                    <div className="grid grid-cols-5 gap-2 bg-black/30 p-4 rounded-xl">
                                                        {(Object.entries(selectedMember.roots) as [string, number][]).map(([key, val]) => (
                                                            <div key={key} className="flex flex-col items-center gap-1">
                                                                <div className={`w-8 h-8 sm:w-12 sm:h-12 rounded-full border flex items-center justify-center ${getElementColorClass(key, val)} shadow-inner`}>
                                                                    <span className="text-[10px] sm:text-xs">{getElementName(key)}</span>
                                                                </div>
                                                                <span className={`text-xs font-bold ${val > 0 ? getElementColorClass(key, val).split(' ')[0] : 'text-gray-800'}`}>{val}</span>
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>

                                                {selectedMember.divineAbilities.length > 0 && (
                                                    <div>
                                                        <h4 className="text-orange-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-orange-900/10 pb-2 mb-4">✨ 已觉醒神通</h4>
                                                        <div className="flex flex-wrap gap-2">
                                                            {selectedMember.divineAbilities.map(ability => (
                                                                <div key={ability} className="px-4 py-2 bg-orange-900/10 border border-orange-500/30 rounded text-orange-200 text-xs font-bold shadow-sm">
                                                                    {ability}
                                                                </div>
                                                            ))}
                                                        </div>
                                                    </div>
                                                )}
                                            </div>
                                        )}
                                        {detailTab === 'talents' && (
                                            <div className="space-y-8 animate-fade-in">
                                                <div>
                                                    <h4 className="text-red-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-red-900/10 pb-2 mb-4">⚔️ 战斗造诣</h4>
                                                    <div className="grid grid-cols-2 sm:grid-cols-5 gap-3">
                                                        {(Object.entries(selectedMember.talents.combat) as [string, number][]).map(([key, val]) => (
                                                            <div key={key} className="bg-black/20 p-2 sm:p-3 rounded-lg border border-white/5 text-center">
                                                                <p className="text-[8px] text-gray-500 uppercase">{key}</p>
                                                                <p className="text-sm font-bold text-gray-100">{Math.floor(val)}</p>
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>
                                                <div>
                                                    <h4 className="text-blue-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-blue-900/10 pb-2 mb-4">🧪 百艺天赋</h4>
                                                    <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                                                        {(Object.entries(selectedMember.talents.professions) as [string, number][]).map(([key, val]) => (
                                                            <div key={key} className="bg-black/20 p-2 sm:p-3 rounded-lg border border-white/5 text-center">
                                                                <p className="text-[8px] text-gray-500 uppercase">{key}</p>
                                                                <p className="text-sm font-bold text-gray-100">{Math.floor(val)}</p>
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>
                                            </div>
                                        )}
                                        {detailTab === 'plan' && (
                                            <div className="space-y-2 animate-fade-in max-w-xl mx-auto">
                                                {(Object.keys(DEVELOPMENT_PLANS) as DevelopmentPlan[]).map(planKey => (
                                                    <button
                                                        key={planKey}
                                                        onClick={() => onUpdateMember(selectedMember.id, { developmentPlan: planKey })}
                                                        className={`w-full p-4 rounded-lg border transition-all text-left ${selectedMember.developmentPlan === planKey ? 'bg-purple-900/20 border-purple-500 shadow-[0_0_15px_rgba(168,85,247,0.2)]' : 'bg-black/20 border-white/5'}`}
                                                    >
                                                        <p className="text-sm font-bold">{DEVELOPMENT_PLANS[planKey].label}</p>
                                                        <p className="text-[10px] text-gray-500">{DEVELOPMENT_PLANS[planKey].desc}</p>
                                                    </button>
                                                ))}
                                            </div>
                                        )}
                                        {detailTab === 'position' && (
                                            <div className="grid grid-cols-2 sm:grid-cols-3 gap-2 animate-fade-in max-w-xl mx-auto">
                                                {POSITIONS.map(pos => (
                                                    <button
                                                        key={pos}
                                                        onClick={() => onUpdateMember(selectedMember.id, { position: pos })}
                                                        className={`p-3 rounded-lg border text-xs sm:text-sm font-bold transition-all ${selectedMember.position === pos ? 'bg-orange-900/20 border-orange-500 text-orange-400' : 'bg-black/20 border-white/5 text-gray-500'}`}
                                                    >{pos}</button>
                                                ))}
                                            </div>
                                        )}
                                        {detailTab === 'tasks' && (
                                            <div className="space-y-2 animate-fade-in max-w-xl mx-auto">
                                                {(Object.keys(TASK_INFO) as TaskType[]).map(task => (
                                                    <button
                                                        key={task}
                                                        onClick={() => onUpdateMember(selectedMember.id, { assignment: task })}
                                                        className={`w-full p-4 rounded-lg border transition-all text-left ${selectedMember.assignment === task ? 'bg-yellow-900/20 border-yellow-500 text-yellow-100 shadow-[0_0_15px_rgba(234,179,8,0.1)]' : 'bg-black/20 border-white/5 text-gray-500'}`}
                                                    >
                                                        <p className="text-sm font-bold">{TASK_INFO[task].label}</p>
                                                        <p className="text-[10px] opacity-60">{TASK_INFO[task].desc}</p>
                                                    </button>
                                                ))}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default ClanDashboard;

export enum Realm {
    QiRefinement = '练气',
    FoundationEstablishment = '筑基',
    Zifu = '紫府',
    JinDan = '金丹',
    YuanShen = '元神'
}

export enum Element {
    Gold = '金',
    Wood = '木',
    Water = '水',
    Fire = '火',
    Earth = '土'
}

export type TaskType = 'Cultivation' | 'Exploration' | 'Research' | 'Patrol' | 'Idle' | 'Mission';
export type TalentTier = '凡人' | '庸才' | '普通' | '超凡' | '天才' | '绝世' | '绝世天骄';
export type RootGrade = '凡胎' | '伪灵根' | '下品灵根' | '中品灵根' | '极品灵根';
export type DevelopmentPlan = 'Combat' | 'Alchemy' | 'Smithing' | 'Talisman' | 'Balanced';
export type MethodTier = '低等' | '中等' | '高等' | '绝世';
export type MethodType = 'Cultivation' | 'Combat' | 'Movement';

export interface CultivationMethod {
    id: string;
    name: string;
    tier: MethodTier;
    type: MethodType;
    element: Element | '无';
    desc: string;
    bonus: string;
}

export interface ElementalRoots {
    gold: number;
    wood: number;
    water: number;
    fire: number;
    earth: number;
}

export interface SpecializedTalents {
    战斗天赋: {
        剑法: number;
        拳法: number;
        枪法: number;
        刀法: number;
        弓箭: number;
    };
    百艺天赋: {
        炼丹: number;
        炼器: number;
        制符: number;
        阵法: number;
    };
}

export interface ClanMember {
    id: string;
    name: string;
    gender: '男' | '女';
    generation: number; 
    realm: Realm;
    subRealm: number; 
    age: number;
    maxAge: number;
    physique: string;       // 体质
    aptitude: number;       // 资质
    comprehension: number;  // 悟性
    divineSense: number;    // 神识
