    status: 'healthy' | 'injured' | 'dead';
    loyalty: number; 
    assignment: TaskType;
    legacyPoints: number; 
    deathYear?: number;

    mainMethodId: string | null;     // 修行功法
    movementMethodId: string | null; // 遁术
    auxMethodIds: string[];         // 战斗功法 (Max 4)
    cultivationProgress: number;     // 0-100
