import React, { useState, useMemo } from 'react';
import { GameState, ClanMember, Realm, TaskType, DevelopmentPlan, CultivationMethod, MethodType } from '../types';
import { TASK_INFO, REALM_ORDER, DEVELOPMENT_PLANS, CULTIVATION_METHODS, POSITIONS, PHYSIQUE_DETAILS, ABILITY_DETAILS } from '../constants';

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddMember: () => void;
}

const ITEMS_PER_PAGE = 8;

const ClanDashboard: React.FC<Props> = ({ state, onUpdateMember, onAddMember }) => {
    const [selectedMemberId, setSelectedMemberId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'alive' | 'deceased'>('alive');
    const [currentPage, setCurrentPage] = useState(0);
    const [detailTab, setDetailTab] = useState<'attr' | 'talents' | 'tasks' | 'cultivation' | 'plan' | 'position'>('attr');

    const [focusedSlot, setFocusedSlot] = useState<string | null>(null);
    const [focusedLibraryMethodId, setFocusedLibraryMethodId] = useState<string | null>(null);

    const selectedMember = useMemo(() => 
        state.members.find(m => m.id === selectedMemberId), 
    [state.members, selectedMemberId]);

    const [libraryType, setLibraryType] = useState<MethodType>('Cultivation');

    const filteredMembers = useMemo(() => {
        const list = state.members.filter(m => activeTab === 'alive' ? m.status !== 'dead' : m.status === 'dead');
        return list.sort((a, b) => {
            if (activeTab === 'alive') {
                const realmDiff = REALM_ORDER.indexOf(b.realm) - REALM_ORDER.indexOf(a.realm);
                if (realmDiff !== 0) return realmDiff;
                return b.subRealm - a.subRealm;
            }
            return (b.deathYear || 0) - (a.deathYear || 0);
        });
    }, [state.members, activeTab]);

    const pagedMembers = filteredMembers.slice(currentPage * ITEMS_PER_PAGE, (currentPage + 1) * ITEMS_PER_PAGE);

    const handleTabChange = (tab: 'alive' | 'deceased') => {
        setActiveTab(tab);
        setCurrentPage(0);
        setSelectedMemberId(null);
    };

    const getGradeColor = (grade: number) => {
        if (grade <= 2) return 'border-slate-300 text-slate-100 bg-slate-500/10 shadow-[0_0_5px_rgba(255,255,255,0.1)]'; // 白色
        if (grade <= 4) return 'border-emerald-500 text-emerald-400 bg-emerald-500/10 shadow-[0_0_8px_rgba(16,185,129,0.2)]'; // 绿色
        if (grade <= 6) return 'border-sky-500 text-sky-400 bg-sky-500/10 shadow-[0_0_10px_rgba(14,165,233,0.3)]'; // 蓝色
        if (grade === 7) return 'border-orange-500 text-orange-400 bg-orange-500/10 shadow-[0_0_12px_rgba(249,115,22,0.4)]'; // 橙色
        if (grade === 8) return 'border-yellow-500 text-yellow-400 bg-yellow-500/10 shadow-[0_0_15px_rgba(234,179,8,0.5)]'; // 金色
        return 'border-rose-600 text-rose-500 bg-rose-600/10 shadow-[0_0_20px_rgba(244,63,94,0.6)] animate-pulse'; // 红色
    };

    const getGradeText = (method: CultivationMethod) => {
        const numerals = ['','一','二','三','四','五','六','七','八','九'];
        return `${numerals[method.grade]}品${method.quality}`;
    };

    const toggleMethod = (methodId: string, type: MethodType) => {
        if (!selectedMember) return;

        if (type === 'Cultivation') {
            onUpdateMember(selectedMember.id, { mainMethodId: selectedMember.mainMethodId === methodId ? null : methodId });
        } else if (type === 'Movement') {
            onUpdateMember(selectedMember.id, { movementMethodId: selectedMember.movementMethodId === methodId ? null : methodId });
        } else if (type === 'Combat') {
            const currentAux = selectedMember.auxMethodIds;
            if (currentAux.includes(methodId)) {
                onUpdateMember(selectedMember.id, { auxMethodIds: currentAux.filter(mid => mid !== methodId) });
            } else if (currentAux.length < 4) {
                onUpdateMember(selectedMember.id, { auxMethodIds: [...currentAux, methodId] });
            }
        }
        setFocusedSlot(null);
        setFocusedLibraryMethodId(null);
    };

    const getElementColorClass = (key: string, val: number) => {
        if (val === 0) return 'text-gray-600 border-gray-800 opacity-30';
        switch (key) {
            case 'gold': return 'text-yellow-400 border-yellow-500 bg-yellow-500/10';
            case 'wood': return 'text-green-400 border-green-500 bg-green-500/10';
            case 'water': return 'text-blue-400 border-blue-500 bg-blue-500/10';
            case 'fire': return 'text-red-400 border-red-500 bg-red-500/10';
            case 'earth': return 'text-orange-700 border-orange-800 bg-orange-800/10';
            default: return 'text-gray-400 border-gray-500';
        }
    };

    const getElementName = (key: string) => {
        switch (key) {
            case 'gold': return '金';
            case 'wood': return '木';
            case 'water': return '水';
            case 'fire': return '火';
            case 'earth': return '土';
            default: return key;
        }
    };

    const libraryMethods = useMemo(() => {
        return CULTIVATION_METHODS.filter(m => m.type === libraryType);
    }, [libraryType]);

    const MethodTooltip = ({ method }: { method: CultivationMethod }) => (
        <div className="absolute z-[100] invisible group-hover:visible top-full left-1/2 -translate-x-1/2 mt-2 w-52 sm:w-64 bg-black/95 border-2 border-yellow-900/50 p-4 rounded shadow-2xl pointer-events-none backdrop-blur-md">
            <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                <span className="text-yellow-500 font-bold text-sm">{method.name}</span>
                <span className={`text-[10px] px-1.5 py-0.5 rounded-sm font-bold border ${getGradeColor(method.grade)}`}>
                    {getGradeText(method)}
                </span>
            </div>
            <p className="text-[10px] sm:text-xs text-gray-400 mb-3 leading-relaxed italic">{method.desc}</p>

            <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                <p className="text-[10px] text-green-500 font-bold mb-1">【功法效果】</p>
                {method.buffs.cultivationSpeed && (
                    <div className="flex justify-between text-[10px]">
                        <span className="text-gray-500">修炼速度</span>
                        <span className={method.buffs.cultivationSpeed > 0 ? 'text-green-400' : 'text-red-400'}>
                            {method.buffs.cultivationSpeed > 0 ? '+' : ''}{method.buffs.cultivationSpeed}%
                        </span>
                    </div>
                )}
                {method.buffs.attack && (
                    <div className="flex justify-between text-[10px]">
                        <span className="text-gray-500">战斗力</span>
                        <span className="text-orange-400">+{method.buffs.attack}%</span>
                    </div>
                )}
                {method.buffs.defense && (
                    <div className="flex justify-between text-[10px]">
                        <span className="text-gray-500">防御力</span>
                        <span className="text-blue-400">+{method.buffs.defense}%</span>
                    </div>
                )}
                {method.buffs.maxAge && (
                    <div className="flex justify-between text-[10px]">
                        <span className="text-gray-500">延寿</span>
                        <span className="text-emerald-400">+{method.buffs.maxAge} 载</span>
                    </div>
                )}
                <p className="text-[9px] text-yellow-600/80 mt-2 italic">"{method.bonus}"</p>
            </div>
        </div>
    );

    const renderSlotItem = (methodId: string | null, type: MethodType, label: string, slotKey: string) => {
        const method = CULTIVATION_METHODS.find(m => m.id === methodId);
        const isFocused = focusedSlot === slotKey;

        return (
            <div className="flex flex-col items-center gap-1 group">
                <div 
                    onClick={() => methodId && setFocusedSlot(isFocused ? null : slotKey)}
                    className={`relative cursor-pointer transition-all duration-300 rounded flex items-center justify-center 
                        ${type === 'Cultivation' ? 'w-16 h-16 sm:w-24 sm:h-24 border-4 border-yellow-600/20' : 'w-12 h-12 sm:w-16 sm:h-16 border-2 border-yellow-900/20'} 
                        bg-black/50 overflow-hidden hover:border-yellow-500/50`}
                >
                    {method ? (
                        <div className={`w-full h-full border-2 p-1 flex flex-col items-center justify-center text-center font-bold ${getGradeColor(method.grade)}`}>
                            <span className={type === 'Cultivation' ? 'text-[10px] sm:text-xs' : 'text-[7px] sm:text-[8px]'}>{method.name}</span>
                        </div>
                    ) : (
                        <div className="text-gray-800 text-[8px] sm:text-[10px] opacity-40 italic">{label}</div>
                    )}

                    {methodId && isFocused && (
                        <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center p-1 animate-fade-in z-20">
                            <button 
                                onClick={(e) => { e.stopPropagation(); toggleMethod(methodId, type); }}
                                className="bg-red-900/80 hover:bg-red-700 text-white text-[9px] sm:text-[10px] py-1 px-3 rounded-full border border-red-500/50 shadow-lg"
                            >
                                卸下
                            </button>
                        </div>
                    )}
                </div>
                <span className="text-[8px] sm:text-[10px] text-yellow-700/80 font-bold bg-black/30 px-2 sm:px-3 py-0.5 rounded-full border border-yellow-900/10">{label}</span>
                {method && <MethodTooltip method={method} />}
            </div>
        );
    };

    return (
        <div className="bg-[#1e130c] border-l-4 border-yellow-800 h-full flex flex-col relative overflow-hidden font-serif shadow-2xl">
            <div className="p-4 border-b border-yellow-900/30 bg-black/40 shrink-0">
                <div className="flex justify-between items-center mb-4">
                    <h2 className="text-xl font-cursive text-yellow-500">⛩️ 族谱常青</h2>
                    <span className="text-[10px] text-yellow-700 bg-black/50 px-3 py-1 rounded-full border border-yellow-900/20">
                        底蕴: {state.heritagePool}
                    </span>
                </div>
                <div className="grid grid-cols-2 gap-2 mb-4">
                    <div className="bg-[#2c1810]/50 p-2 rounded border border-yellow-900/20">
                        <p className="text-[9px] text-gray-500">家族灵石</p>
                        <p className="text-yellow-400 font-bold text-sm">✨ {state.spiritStones}</p>
                    </div>
                    <div className="bg-[#2c1810]/50 p-2 rounded border border-yellow-900/20">
                        <p className="text-[9px] text-gray-500">族人数量</p>
                        <p className="text-blue-400 font-bold text-sm">👥 {state.members.filter(m => m.status !== 'dead').length}</p>
                    </div>
                </div>
                <div className="flex p-1 bg-black/40 rounded-lg gap-1 border border-yellow-900/10">
                    <button onClick={() => handleTabChange('alive')} className={`flex-1 py-1.5 text-xs rounded transition-all ${activeTab === 'alive' ? 'bg-yellow-800 text-yellow-100 shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}>在世族人</button>
                    <button onClick={() => handleTabChange('deceased')} className={`flex-1 py-1.5 text-xs rounded transition-all ${activeTab === 'deceased' ? 'bg-gray-800 text-gray-100' : 'text-gray-500 hover:text-gray-300'}`}>英灵祠堂</button>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-2 scrollbar-hide">
                {activeTab === 'alive' && (
                    <button onClick={onAddMember} className="w-full bg-green-900/20 hover:bg-green-800/40 text-green-400 border border-green-900/50 py-2 rounded text-xs transition-all flex items-center justify-center gap-2 mb-4 group">
                        <span>👶</span> 诞育麟儿
                    </button>
                )}
                {pagedMembers.length > 0 ? pagedMembers.map(member => (
                    <div 
                        key={member.id} onClick={() => activeTab === 'alive' && setSelectedMemberId(member.id)}
                        className={`group p-3 rounded-md border transition-all cursor-pointer ${selectedMemberId === member.id ? 'bg-[#2d1e15] border-yellow-600 scale-[1.02] shadow-xl' : 'bg-[#1e130c] border-yellow-900/30 hover:border-yellow-700/50'}`}
                    >
                        <div className="flex justify-between items-center mb-1">
                            <div className="flex items-center gap-2">
                                <span className="font-bold text-sm text-yellow-100/90">{member.name}</span>
                                <span className="text-[8px] text-orange-400 opacity-60">[{member.position}]</span>
                                {member.assignment === 'Cultivation' && <span className="text-[8px] animate-pulse text-blue-400">修炼中</span>}
                            </div>
                            <span className={`text-[9px] px-1.5 py-0.5 rounded-sm bg-yellow-900/40 text-yellow-500 border border-yellow-700/20`}>{member.realm}</span>
                        </div>
                        <div className="flex justify-between text-[10px] text-gray-500">
                            <span>评级: <span className="text-yellow-700 font-bold">{member.tier}</span></span>
                            <span className="text-[9px] opacity-70 italic">{member.rootGrade}</span>
                        </div>
                        {activeTab === 'alive' && (
                            <div className="mt-2 w-full h-1 bg-black/40 rounded-full overflow-hidden border border-white/5">
                                <div className="h-full bg-blue-500/60" style={{ width: `${member.cultivationProgress}%` }}></div>
                            </div>
                        )}
                    </div>
                )) : (
                    <div className="py-20 text-center text-gray-700 opacity-40 italic">空空如也</div>
                )}
            </div>

            {selectedMember && activeTab === 'alive' && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 p-2 sm:p-4 font-serif">
                    <div className="relative w-full max-w-6xl h-full sm:h-[90vh] bg-[#1a2521] border-[4px] sm:border-[12px] border-[#2c3e34] rounded-sm shadow-2xl overflow-hidden flex flex-col">
                        <div className="h-14 bg-[#141e1b] border-b border-[#2c3e34] flex items-center px-4 sm:px-8 gap-2 sm:gap-4 overflow-x-auto scrollbar-hide shrink-0">
                            <div className="flex items-center gap-1 sm:gap-2">
                                <button onClick={() => setDetailTab('attr')} className={`whitespace-nowrap px-2 sm:px-4 py-1 text-[10px] sm:text-xs transition-all border-b-2 ${detailTab === 'attr' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>👤 属性</button>
                                <button onClick={() => setDetailTab('talents')} className={`whitespace-nowrap px-2 sm:px-4 py-1 text-[10px] sm:text-xs transition-all border-b-2 ${detailTab === 'talents' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>📜 天赋</button>
                                <button onClick={() => setDetailTab('cultivation')} className={`whitespace-nowrap px-2 sm:px-4 py-1 text-[10px] sm:text-xs transition-all border-b-2 ${detailTab === 'cultivation' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>🌀 功法</button>
                                <button onClick={() => setDetailTab('plan')} className={`whitespace-nowrap px-2 sm:px-4 py-1 text-[10px] sm:text-xs transition-all border-b-2 ${detailTab === 'plan' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>🗺️ 计划</button>
                                <button onClick={() => setDetailTab('position')} className={`whitespace-nowrap px-2 sm:px-4 py-1 text-[10px] sm:text-xs transition-all border-b-2 ${detailTab === 'position' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>🏵️ 册封</button>
                                <button onClick={() => setDetailTab('tasks')} className={`whitespace-nowrap px-2 sm:px-4 py-1 text-[10px] sm:text-xs transition-all border-b-2 ${detailTab === 'tasks' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>🎯 指派</button>
                            </div>
                            <button onClick={() => setSelectedMemberId(null)} className="ml-auto w-8 h-8 bg-red-900/20 hover:bg-red-900/40 text-red-500 rounded-full flex items-center justify-center text-xl transition-all">×</button>
                        </div>

                        <div className="flex-1 flex flex-col sm:flex-row overflow-hidden relative">
                            {detailTab === 'cultivation' ? (
                                <div className="flex-1 flex flex-col sm:flex-row bg-[#0c1310] relative animate-fade-in overflow-hidden">
                                    <div className="w-full sm:w-[40%] p-4 flex flex-col items-center justify-center relative border-b sm:border-b-0 sm:border-r border-white/5 overflow-y-auto shrink-0">
                                        <div className="relative w-full flex flex-col items-center justify-center gap-4 sm:gap-6 py-4">
                                            {renderSlotItem(selectedMember.movementMethodId, 'Movement', '遁术', 'mov')}
                                            <div className="flex items-center gap-4 sm:gap-8">
                                                <div className="flex flex-col gap-2 sm:gap-4">
                                                    {renderSlotItem(selectedMember.auxMethodIds[0] || null, 'Combat', '辅修', 'aux0')}
                                                    {renderSlotItem(selectedMember.auxMethodIds[1] || null, 'Combat', '辅修', 'aux1')}
                                                </div>
                                                <div className="w-16 h-16 sm:w-24 sm:h-24 relative flex items-center justify-center shrink-0">
                                                    <div className="text-4xl sm:text-6xl opacity-30 animate-pulse">🧘</div>
                                                </div>
                                                <div className="flex flex-col gap-2 sm:gap-4">
                                                    {renderSlotItem(selectedMember.auxMethodIds[2] || null, 'Combat', '辅修', 'aux2')}
                                                    {renderSlotItem(selectedMember.auxMethodIds[3] || null, 'Combat', '辅修', 'aux3')}
                                                </div>
                                            </div>
                                            {renderSlotItem(selectedMember.mainMethodId, 'Cultivation', '主修', 'main')}
                                        </div>
                                    </div>

                                    <div className="flex-1 p-4 sm:p-6 bg-black/20 flex flex-col h-full border-l border-white/5 overflow-hidden">
                                        <div className="flex justify-between items-center mb-4 shrink-0">
                                            <div className="flex gap-1 p-1 bg-black/40 rounded-lg border border-yellow-900/20">
                                                <button onClick={() => setLibraryType('Cultivation')} className={`px-2 sm:px-4 py-1 text-[10px] sm:text-xs rounded transition-all ${libraryType === 'Cultivation' ? 'bg-yellow-800 text-yellow-100 font-bold' : 'text-gray-500'}`}>修行</button>
                                                <button onClick={() => setLibraryType('Combat')} className={`px-2 sm:px-4 py-1 text-[10px] sm:text-xs rounded transition-all ${libraryType === 'Combat' ? 'bg-red-900 text-yellow-100 font-bold' : 'text-gray-500'}`}>战斗</button>
                                                <button onClick={() => setLibraryType('Movement')} className={`px-2 sm:px-4 py-1 text-[10px] sm:text-xs rounded transition-all ${libraryType === 'Movement' ? 'bg-blue-900 text-yellow-100 font-bold' : 'text-gray-500'}`}>遁术</button>
                                            </div>
                                        </div>

                                        <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-2 sm:gap-4 auto-rows-max pb-8">
                                            {libraryMethods.map(method => {
                                                const isEquipped = selectedMember.mainMethodId === method.id || 
                                                                 selectedMember.movementMethodId === method.id || 
                                                                 selectedMember.auxMethodIds.includes(method.id);
                                                const isFocused = focusedLibraryMethodId === method.id;

                                                return (
                                                    <div key={method.id} className="relative group">
                                                        <button 
                                                            onClick={() => !isEquipped && setFocusedLibraryMethodId(isFocused ? null : method.id)}
                                                            className={`w-full aspect-square rounded border-2 p-1 sm:p-2 flex flex-col items-center justify-center gap-1 transition-all relative
                                                            ${getGradeColor(method.grade)} 
                                                            ${isEquipped ? 'ring-1 ring-yellow-500 brightness-75 cursor-default' : 'opacity-70 hover:opacity-100'}`}
                                                        >
                                                            {isEquipped && <div className="absolute -top-1 -right-1 w-3 h-3 bg-yellow-500 text-black text-[8px] rounded-full flex items-center justify-center font-bold z-10">✓</div>}
                                                            <span className="text-[10px] sm:text-xs font-bold text-center leading-tight truncate w-full">{method.name}</span>
                                                        </button>

                                                        {!isEquipped && isFocused && (
                                                            <div className="absolute inset-0 bg-black/90 flex flex-col items-center justify-center p-1 rounded z-20 animate-fade-in border border-yellow-500/30">
                                                                <button 
                                                                    onClick={(e) => { e.stopPropagation(); toggleMethod(method.id, method.type); }}
                                                                    className="bg-green-900/80 hover:bg-green-700 text-white text-[8px] sm:text-[10px] py-1 px-2 sm:px-4 rounded-full border border-green-500/50 font-bold"
                                                                >修炼</button>
