                                                        key={pos}
                                                        onClick={() => onUpdateMember(selectedMember.id, { position: pos })}
                                                        className={`p-3 rounded-lg border text-xs sm:text-sm font-bold transition-all ${selectedMember.position === pos ? 'bg-orange-900/20 border-orange-500 text-orange-400' : 'bg-black/20 border-white/5 text-gray-500'}`}
                                                    >{pos}</button>
                                                ))}
                                            </div>
                                        )}
                                        {detailTab === 'tasks' && (
                                            <div className="space-y-2 animate-fade-in max-w-xl mx-auto">
                                                {(Object.keys(TASK_INFO) as TaskType[]).map(task => (
