    const [isConsoleCollapsed, setIsConsoleCollapsed] = useState(false);

    const getRootGrade = (roots: ElementalRoots): RootGrade => {
        const vals = Object.values(roots);
        const activeCount = vals.filter(v => v > 0).length;
        const maxVal = Math.max(...vals);
        const highCount = vals.filter(v => v > 5).length;
        const veryHighCount = vals.filter(v => v > 6).length;

        if (activeCount === 0) return '凡胎';
        if (activeCount === 5 && (veryHighCount >= 3 || maxVal > 9)) return '极品灵根';
        if (activeCount >= 3 && (highCount >= 2 || maxVal > 7)) return '中品灵根';
        if (activeCount <= 2 && maxVal > 5) return '下品灵根';
        return '伪灵根'; 
    };

    const getOverallTier = (aptitude: number, rootGrade: RootGrade): TalentTier => {
        if (rootGrade === '凡胎') return '凡人';
        if (rootGrade === '伪灵根' && aptitude < 30) return '庸才';
        if (aptitude > 95 || (rootGrade === '极品灵根' && aptitude > 90)) return '绝世天骄';
        if (aptitude > 85 || rootGrade === '极品灵根') return '绝世';
        if (aptitude > 70 || rootGrade === '中品灵根') return '天才';
        if (aptitude > 50) return '超凡';
        if (aptitude > 30) return '普通';
        return '庸才';
    };

    const handleUpdateMember = (id: string, updates: Partial<ClanMember>) => {
        setState(prev => ({
            ...prev,
            members: prev.members.map(m => m.id === id ? { ...m, ...updates } : m)
        }));
    };

    const handleUpdateRegion = (id: string, updates: Partial<Region>) => {
        setState(prev => ({
            ...prev,
            regions: prev.regions.map(r => r.id === id ? { ...r, ...updates } : r)
        }));
    };

    const handleAddMember = () => {
        if (state.spiritStones < 100) {
            setState(p => ({ ...p, logs: ["灵石短缺，无力供养更多新丁。", ...p.logs].slice(0, 15) }));
            return;
        }

        const genIdx = Math.floor(state.year / 40) % GENERATIONS.length;
        const genPrefix = GENERATIONS[genIdx];
        const names = ['清', '锋', '明', '煌', '守', '信', '元', '载', '宏', '远', '志', '浩'];
        const randomName = names[Math.floor(Math.random() * names.length)];
        const gender = Math.random() > 0.5 ? '男' : '女';

        const rootRolls = {
            gold: Math.random() > 0.6 ? Math.floor(Math.random() * 10) + 1 : 0,
            wood: Math.random() > 0.6 ? Math.floor(Math.random() * 10) + 1 : 0,
            water: Math.random() > 0.6 ? Math.floor(Math.random() * 10) + 1 : 0,
            fire: Math.random() > 0.6 ? Math.floor(Math.random() * 10) + 1 : 0,
            earth: Math.random() > 0.6 ? Math.floor(Math.random() * 10) + 1 : 0,
        };

        const rootGrade = getRootGrade(rootRolls);
        const aptitude = 10 + Math.floor(Math.random() * 80) + (rootGrade === '极品灵根' ? 10 : 0);
        const comprehension = 20 + Math.floor(Math.random() * 70);
        const divineSense = 5 + Math.floor(Math.random() * 30);
        const tier = getOverallTier(aptitude, rootGrade);

        const talents: SpecializedTalents = {
            战斗天赋: {
                剑法: Math.floor(Math.random() * 60),
                拳法: Math.floor(Math.random() * 60),
                枪法: Math.floor(Math.random() * 60),
                刀法: Math.floor(Math.random() * 60),
                弓箭: Math.floor(Math.random() * 60),
            },
            百艺天赋: {
                炼丹: Math.floor(Math.random() * 60),
                炼器: Math.floor(Math.random() * 60),
                制符: Math.floor(Math.random() * 60),
                阵法: Math.floor(Math.random() * 60),
            }
        };

        // 特殊的天才可能出生就有神通
        const bornAbilities: string[] = [];
        if (tier === '绝世天骄' || tier === '绝世') {
            if (Math.random() < 0.2) {
                const randomAbility = ABILITIES[Math.floor(Math.random() * ABILITIES.length)];
                bornAbilities.push(randomAbility);
            }
        }

        const newMember: ClanMember = {
            id: `member-${Date.now()}-${Math.random()}`,
            name: `${SURNAMES[0]}${genPrefix}${randomName}`,
            gender: gender as '男' | '女',
            generation: genIdx,
            realm: Realm.QiRefinement,
            subRealm: 1,
            age: 8 + Math.floor(Math.random() * 10),
            maxAge: 75 + Math.floor(Math.random() * 45),
            physique: rootGrade === '凡胎' ? '凡人' : PHYSIQUES[Math.floor(Math.random() * PHYSIQUES.length)],
            aptitude,
            comprehension,
            divineSense,
            roots: rootRolls,
            rootGrade,
            talents,
            tier,
            element: [Element.Gold, Element.Wood, Element.Water, Element.Fire, Element.Earth][Math.floor(Math.random() * 5)],
            status: 'healthy',
            loyalty: 75 + Math.floor(Math.random() * 25),
            assignment: 'Idle',
            legacyPoints: 0,
            mainMethodId: rootGrade === '凡胎' ? null : 'm1',
            movementMethodId: null,
            auxMethodIds: [],
            cultivationProgress: 0,
            developmentPlan: 'Balanced',
            divineAbilities: bornAbilities,
            sect: '望月李氏',
            position: '寻常族子'
        };

        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones - 100,
            members: [...prev.members, newMember],
            logs: [`【族讯】李氏子弟 ${newMember.name} 测得【${newMember.rootGrade}】，评级【${newMember.tier}】。${bornAbilities.length > 0 ? `且有天生神通【${bornAbilities[0]}】！` : ''}`, ...prev.logs].slice(0, 15)
        }));
    };

    const handleNextYear = async () => {
        setIsProcessing(true);
        let yearLogs: string[] = [];
        let stoneGain = 150;
        let heritageGain = 0;
        let justDiedRef: ClanMember | null = null;
        let casualties: string[] = [];
        let injuredMemberIds: string[] = [];

        const updatedRegions = state.regions.map(region => {
            if (!region.activeMission) return region;
            const mission = region.activeMission;
            const turnsRemaining = mission.turnsRemaining - 1;
            if (turnsRemaining <= 0) {
                const member = state.members.find(m => m.id === mission.memberId);
                if (member) {
                    if (region.category === 'Natural') {
                        const gain = 50 + region.difficulty * 20 + Math.floor(Math.random() * 50);
                        stoneGain += gain;
                        yearLogs.push(`【派遣】${member.name} 完成 ${region.name} 的巡视，带回灵石 ${gain}。`);
                    } else if (region.category === 'Mystic') {
                        const gain = 200 + region.difficulty * 50 + Math.floor(Math.random() * 150);
                        stoneGain += gain;
                        heritageGain += 10;
                        yearLogs.push(`【探险】${member.name} 从秘境 ${region.name} 归来，收获灵石 ${gain}。`);
                        const risk = region.difficulty * 5;
                        if (Math.random() * 100 < risk) {
                            if (Math.random() > 0.7) {
                                casualties.push(member.id);
                                yearLogs.push(`【惨痛】${member.name} 在秘境遭遇伏击陨落。`);
                            } else {
                                injuredMemberIds.push(member.id);
                                yearLogs.push(`【负伤】${member.name} 在秘境身受重伤。`);
                            }
                        }
                    }
                }
                return { ...region, activeMission: undefined };
            }
            return { ...region, activeMission: { ...mission, turnsRemaining } };
        });

        const updatedMembers: ClanMember[] = state.members.map(member => {
            if (member.status === 'dead') return member;
            let m: ClanMember = { ...member };
            m.age += 1;
            if (casualties.includes(m.id)) { m.status = 'dead'; m.deathYear = state.year; return m; }
            if (injuredMemberIds.includes(m.id)) { m.status = 'injured'; }
            const isMissionFinished = state.regions.some(r => r.activeMission?.memberId === m.id && r.activeMission.turnsRemaining === 1);
            if (m.assignment === 'Mission' && isMissionFinished) { m.assignment = 'Idle'; }

            const newTalents = {
                战斗天赋: { ...m.talents.战斗天赋 },
                百艺天赋: { ...m.talents.百艺天赋 }
            };
            if (m.developmentPlan === 'Combat') newTalents.战斗天赋.剑法 = Math.min(100, newTalents.战斗天赋.剑法 + 0.1);
            if (m.developmentPlan === 'Alchemy') newTalents.百艺天赋.炼丹 = Math.min(100, newTalents.百艺天赋.炼丹 + 0.1);
            if (m.developmentPlan === 'Smithing') newTalents.百艺天赋.炼器 = Math.min(100, newTalents.百艺天赋.炼器 + 0.1);
            m.talents = newTalents;

            // 应用功法 Buff
            const equippedMethods = [
                CULTIVATION_METHODS.find(method => method.id === m.mainMethodId),
                CULTIVATION_METHODS.find(method => method.id === m.movementMethodId),
                ...m.auxMethodIds.map(aid => CULTIVATION_METHODS.find(method => method.id === aid))
            ].filter(Boolean) as CultivationMethod[];

            const speedBuff = equippedMethods.reduce((acc, curr) => acc + (curr.buffs.cultivationSpeed || 0), 0);

            switch (m.assignment) {
                case 'Cultivation':
                    const luckFactor = 1 + (state.luck / 200); 
                    const rootModifier = m.rootGrade === '极品灵根' ? 1.5 : m.rootGrade === '中品灵根' ? 1.2 : m.rootGrade === '下品灵根' ? 1.0 : 0.7;
                    const methodModifier = 1 + (speedBuff / 100);
                    m.cultivationProgress += (m.aptitude / 10) * luckFactor * rootModifier * methodModifier;
                    if (m.cultivationProgress >= 100) {
                        m.cultivationProgress = 0;
                        if (m.subRealm < 9) {
                            m.subRealm += 1;
                            yearLogs.push(`修行：${m.name} 突破至 ${m.realm}${m.subRealm}层。`);
                        } else {
                            if (Math.random() < (m.aptitude / 200) * luckFactor) {
                                const currentIndex = REALM_ORDER.indexOf(m.realm);
                                if (currentIndex < REALM_ORDER.length - 1) {
                                    const nextRealm = REALM_ORDER[currentIndex + 1];
                                    m.realm = nextRealm;
                                    m.subRealm = 1;
                                    m.maxAge += (currentIndex + 2) * 50; 
                                    yearLogs.push(`突破：${m.name} 晋升 ${m.realm}！`);

                                    // 晋升元婴时解锁神通
                                    if (nextRealm === Realm.YuanYing && m.divineAbilities.length === 0) {
                                        const randomAbility = ABILITIES[Math.floor(Math.random() * ABILITIES.length)];
                                        m.divineAbilities.push(randomAbility);
                                        yearLogs.push(`悟道：${m.name} 证就元婴，觉醒本命神通【${randomAbility}】！`);
                                    }
                                }
                            }
                        }
                    }
                    m.legacyPoints += 2;
                    break;
                case 'Research': heritageGain += 1; m.legacyPoints += 5; break;
                case 'Patrol': m.loyalty = Math.min(100, m.loyalty + 2); break;
            }
            if (m.age >= m.maxAge && m.status !== 'dead') { m.status = 'dead'; m.deathYear = state.year; yearLogs.push(`陨落：${m.name} 终年 ${m.age} 岁。`); justDiedRef = m; }
            return m;
        });

        const newEvent = await generateYearlyEvent({ ...state, members: updatedMembers });
        setState(prev => ({
            ...prev,
            year: prev.year + 1,
            members: updatedMembers,
            regions: updatedRegions,
            spiritStones: prev.spiritStones + stoneGain,
            heritagePool: prev.heritagePool + heritageGain,
            logs: [...yearLogs, ...prev.logs].slice(0, 15)
        }));
        if (justDiedRef) setInheritanceInfo(justDiedRef);
        setEvent(newEvent);
        setIsProcessing(false);
    };

    const handleEventChoice = (choice: 'A' | 'B') => {
        if (!event) return;
        const impact = event.impact;
        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones + impact.spiritStones,
            merit: prev.merit + impact.merit,
            luck: Math.min(100, Math.max(0, prev.luck + impact.luck)),
            logs: [`【抉择】${impact.log}`, ...prev.logs].slice(0, 15),
        }));
        setEvent(null);
    };

    const handleProcessInheritance = (heirId: string) => {
        if (!inheritanceInfo) return;
        const heir = state.members.find(m => m.id === heirId);
        if (heir) {
            handleUpdateMember(heirId, { aptitude: Math.min(100, heir.aptitude + Math.floor(inheritanceInfo.aptitude * 0.15)) });
        }
        setInheritanceInfo(null);
    };

    return (
        <div className="h-screen w-screen flex flex-col bg-[#0f0a07] text-gray-300 overflow-hidden select-none font-serif">
            <header className="h-16 bg-[#2c1810] border-b-2 border-yellow-900/50 flex items-center justify-between px-8 z-40 shadow-xl">
                <div className="flex items-center gap-12">
                    <div className="flex flex-col">
                        <h1 className="text-2xl font-cursive text-yellow-500 tracking-widest">玄鉴仙族：昊天纪元</h1>
                        <span className="text-[10px] text-yellow-900 font-bold uppercase tracking-[0.3em] -mt-1">Wangyue Li Clan Chronicles</span>
                    </div>
                    <div className="flex gap-6 items-center border-l border-yellow-900/30 pl-8">
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase tracking-tighter">天罡历载</span>
                            <span className="text-lg font-mono text-yellow-100">{state.year}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase tracking-tighter">家族气运</span>
                            <div className="flex items-center gap-2">
                                <div className="w-20 h-1.5 bg-black/40 rounded-full overflow-hidden border border-yellow-900/20">
                                    <div className="h-full bg-purple-600 shadow-[0_0_8px_rgba(147,51,234,0.5)]" style={{ width: `${state.luck}%` }}></div>
                                </div>
                                <span className="text-xs text-purple-400 font-bold">{state.luck}</span>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-4">
                    <button onClick={() => setIsDashboardVisible(!isDashboardVisible)} className={`px-5 py-2 rounded-full border transition-all text-xs font-bold flex items-center gap-2 ${isDashboardVisible ? 'bg-yellow-800 border-yellow-500 text-yellow-100' : 'bg-black/40 border-yellow-900 text-gray-500'}`}>
                        <span>📜</span> 族谱
                    </button>
                    <button onClick={handleNextYear} disabled={isProcessing || !!event} className="bg-gradient-to-b from-yellow-700 to-yellow-900 hover:from-yellow-600 hover:to-yellow-800 disabled:opacity-30 text-white px-8 py-2 rounded border-t border-yellow-500/30 border-b-4 border-black/50 font-bold transition-all text-sm shadow-lg">
                        {isProcessing ? '推演中' : '岁过一载'}
                    </button>
                </div>
            </header>

            <main className="flex-1 flex overflow-hidden">
                <div className="flex-1 relative bg-[#0a0705]">
                    <WorldMap regions={state.regions} members={state.members} currentRegionId={state.currentRegionId} onSelectRegion={(r) => setState(p => ({ ...p, currentRegionId: r ? r.id : '' }))} onUpdateMember={handleUpdateMember} onUpdateRegion={handleUpdateRegion} />
                    <div className={`absolute bottom-6 left-6 transition-all duration-500 ease-in-out parchment border-2 border-[#4a3728] rounded-sm shadow-[0_10px_40px_rgba(0,0,0,0.6)] z-20 opacity-95 hover:opacity-100 flex flex-col ${isConsoleCollapsed ? 'w-48 h-10' : 'w-72 h-56'}`}>
                        <div className="flex justify-between items-center px-4 py-2 border-b border-[#4a3728]/30 bg-black/5">
                            <span className="text-[11px] text-[#2c1810] font-bold uppercase tracking-widest font-cursive">族史摘要</span>
                            <button onClick={() => setIsConsoleCollapsed(!isConsoleCollapsed)} className="text-[#4a3728] hover:text-black transition-colors p-1">
                                <span className="text-lg leading-none">{isConsoleCollapsed ? '▲' : '▼'}</span>
                            </button>
                        </div>
                        {!isConsoleCollapsed && (
                            <div className="flex-1 overflow-y-auto p-4 pt-1 space-y-2.5 custom-scrollbar text-[11px]">
                                {state.logs.map((log, i) => (
                                    <p key={i} className="leading-relaxed text-black/80 font-serif font-bold tracking-tight">
                                        <span className="text-[#8b0000] mr-2">◈</span> {log}
                                    </p>
                                ))}
                            </div>
                        )}
                    </div>
                </div>
                {isDashboardVisible && <div className="w-80 h-full shadow-2xl z-30 animate-slide-left border-l border-yellow-900/50"><ClanDashboard state={state} onUpdateMember={handleUpdateMember} onAddMember={handleAddMember} /></div>}
            </main>

            {inheritanceInfo && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-md p-6">
                    <div className="bg-[#1e130c] w-full max-w-xl p-10 rounded-xl border-4 border-double border-yellow-700 text-center shadow-2xl overflow-hidden max-h-[95vh] flex flex-col">
                        <h2 className="text-3xl font-cursive text-yellow-500 mb-4 shrink-0">祖先遗泽: {inheritanceInfo.name}</h2>
                        <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar space-y-2">
                            {state.members.filter(m => m.status === 'healthy' && m.id !== inheritanceInfo.id).map(heir => (
                                <button key={heir.id} onClick={() => handleProcessInheritance(heir.id)} className="group w-full p-4 bg-yellow-900/5 border border-yellow-900/20 hover:bg-yellow-900/20 hover:border-yellow-500 rounded-lg transition-all flex justify-between items-center">
                                    <div className="text-left">
                                        <div className="text-sm font-bold text-yellow-100 group-hover:text-yellow-400">{heir.name}</div>
                                        <div className="text-[10px] text-gray-500">{heir.realm}{heir.subRealm}层 | 资质: {heir.aptitude}</div>
                                    </div>
                                    <span className="text-[10px] text-blue-400">承袭遗泽</span>
                                </button>
                            ))}
                        </div>
                    </div>
                </div>
            )}

            {event && (
                <div className="fixed inset-0 z-50 flex items-start justify-center bg-black/80 backdrop-blur-sm p-4 pt-20 sm:pt-24 overflow-hidden">
                    <div className="bg-[#f4e4bc] w-full max-w-3xl max-h-[85vh] p-8 sm:p-12 rounded border-[14px] border-[#4a3728] shadow-2xl relative scroll-shadow flex flex-col">
                        <div className="absolute -top-10 left-1/2 -translate-x-1/2 bg-[#4a3728] text-yellow-500 px-10 sm:px-16 py-3 sm:py-4 rounded-b-xl font-cursive text-2xl sm:text-3xl z-10 whitespace-nowrap">{event.title}</div>
                        <div className="flex-1 overflow-y-auto custom-scrollbar mt-4 pr-4">
                            <div className="text-[#2c1810] leading-relaxed text-xl sm:text-2xl font-serif italic text-justify opacity-90 indent-12">{event.content}</div>
                        </div>
                        <div className="mt-8 grid grid-cols-1 sm:grid-cols-2 gap-4 sm:gap-8 relative z-10 shrink-0">
                            <button onClick={() => handleEventChoice('A')} className="group p-4 sm:p-6 border-2 border-[#4a3728]/40 rounded-xl hover:bg-[#4a3728] transition-all text-left">
                                <p className="font-bold text-base sm:text-lg text-[#2c1810] group-hover:text-yellow-400">◈ {event.choiceA.text}</p>
                                <p className="text-[10px] sm:text-xs text-[#2c1810]/60 group-hover:text-yellow-100/60">{event.choiceA.effect}</p>
                            </button>
                            <button onClick={() => handleEventChoice('B')} className="group p-4 sm:p-6 border-2 border-[#4a3728]/40 rounded-xl hover:bg-[#4a3728] transition-all text-left">
                                <p className="font-bold text-base sm:text-lg text-[#2c1810] group-hover:text-yellow-400">◈ {event.choiceB.text}</p>
                                <p className="text-[10px] sm:text-xs text-[#2c1810]/60 group-hover:text-yellow-100/60">{event.choiceB.effect}</p>
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default App;

export enum Realm {
    QiRefinement = '练气',
    FoundationEstablishment = '筑基',
    Zifu = '紫府',
    JinDan = '金丹',
    YuanYing = '元婴',
    YuanShen = '元神'
}

export enum Element {
    Gold = '金',
    Wood = '木',
    Water = '水',
    Fire = '火',
    Earth = '土'
}

export type TaskType = 'Cultivation' | 'Exploration' | 'Research' | 'Patrol' | 'Idle' | 'Mission';
export type TalentTier = '凡人' | '庸才' | '普通' | '超凡' | '天才' | '绝世' | '绝世天骄';
export type RootGrade = '凡胎' | '伪灵根' | '下品灵根' | '中品灵根' | '极品灵根';
export type DevelopmentPlan = 'Combat' | 'Alchemy' | 'Smithing' | 'Talisman' | 'Balanced';
export type MethodQuality = '上等' | '中等' | '下等';
export type MethodType = 'Cultivation' | 'Combat' | 'Movement';

export interface Building {
    id: string;
    type: string;
    level: number;
    assignedMemberId: string | null;
}

export interface MethodBuffs {
    cultivationSpeed?: number;
    attack?: number;
    defense?: number;
    divineSense?: number;
    maxAge?: number;
}

export interface CultivationMethod {
    id: string;
    name: string;
    grade: number;
    quality: MethodQuality;
    type: MethodType;
    element: Element | '无';
    desc: string;
    bonus: string;
    buffs: MethodBuffs;
}

export interface ElementalRoots {
    gold: number;
    wood: number;
    water: number;
    fire: number;
    earth: number;
}

export interface SpecializedTalents {
    战斗天赋: {
        剑法: number;
        拳法: number;
        枪法: number;
        刀法: number;
        弓箭: number;
    };
    百艺天赋: {
        炼丹: number;
        炼器: number;
        制符: number;
        阵法: number;
    };
}

export interface ClanMember {
    id: string;
    name: string;
    gender: '男' | '女';
    generation: number; 
    realm: Realm;
    subRealm: number; 
    age: number;
    maxAge: number;
    physique: string;
    aptitude: number;
    comprehension: number;
    divineSense: number;
    roots: ElementalRoots;
    rootGrade: RootGrade;
    talents: SpecializedTalents;
    tier: TalentTier;

    element: Element;
    status: 'healthy' | 'injured' | 'dead';
    loyalty: number; 
    assignment: TaskType;
    legacyPoints: number; 
    deathYear?: number;

    mainMethodId: string | null;
    movementMethodId: string | null;
    auxMethodIds: string[];
    cultivationProgress: number;
    developmentPlan: DevelopmentPlan;
    divineAbilities: string[];
    sect: string;
    position: string;
}

export type RegionCategory = 'Natural' | 'Stakeholder' | 'Mystic';
export type RegionType = 'lake' | 'mountain' | 'forest' | 'city' | 'sect' | 'ruins' | 'cave';

export interface Region {
    id: string;
    name: string;
    description: string;
    difficulty: number;
    owner: string;
    x: number;
    y: number;
    type: RegionType;
