                                                    <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                                                        {(Object.entries(selectedMember.talents.百艺天赋) as [string, number][]).map(([key, val]) => (
                                                            <div key={key} className="bg-black/20 p-2 sm:p-3 rounded-lg border border-white/5 text-center">
                                                                <p className="text-[10px] text-gray-500">{key}</p>
                                                                <p className="text-sm font-bold text-gray-100">{Math.floor(val)}</p>
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>
                                            </div>
                                        )}
                                        {detailTab === 'plan' && (
                                            <div className="space-y-2 animate-fade-in max-w-xl mx-auto">
                                                {(Object.keys(DEVELOPMENT_PLANS) as DevelopmentPlan[]).map(planKey => (
                                                    <button
                                                        key={planKey}
                                                        onClick={() => onUpdateMember(selectedMember.id, { developmentPlan: planKey })}
                                                        className={`w-full p-4 rounded-lg border transition-all text-left ${selectedMember.developmentPlan === planKey ? 'bg-purple-900/20 border-purple-500 shadow-[0_0_15px_rgba(168,85,247,0.2)]' : 'bg-black/20 border-white/5'}`}
                                                    >
                                                        <p className="text-sm font-bold">{DEVELOPMENT_PLANS[planKey].label}</p>
                                                        <p className="text-[10px] text-gray-500">{DEVELOPMENT_PLANS[planKey].desc}</p>
                                                    </button>
                                                ))}
                                            </div>
                                        )}
                                        {detailTab === 'tasks' && (
                                            <div className="space-y-2 animate-fade-in max-w-xl mx-auto">
                                                {(Object.keys(TASK_INFO) as TaskType[]).map(task => (
                                                    <button
                                                        key={task}
                                                        onClick={() => onUpdateMember(selectedMember.id, { assignment: task })}
                                                        className={`w-full p-4 rounded-lg border transition-all text-left ${selectedMember.assignment === task ? 'bg-yellow-900/20 border-yellow-500 text-yellow-100 shadow-[0_0_15px_rgba(234,179,8,0.1)]' : 'bg-black/20 border-white/5 text-gray-500'}`}
                                                    >
                                                        <p className="text-sm font-bold">{TASK_INFO[task].label}</p>
                                                        <p className="text-[10px] opacity-60">{TASK_INFO[task].desc}</p>
                                                    </button>
                                                ))}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

