        tier: '普通', element: Element.Wood, status: 'healthy', loyalty: 100, assignment: 'Patrol', legacyPoints: 10,
        mainMethodId: 'm1', movementMethodId: 'm10', auxMethodIds: ['m8'], cultivationProgress: 20, developmentPlan: 'Smithing', divineAbilities: [], sect: '望月李氏', position: '寻常族子',
        equipment: { ...defaultEquipment }
    },
    { 
        id: 'tongya', name: '李通崖', gender: '男', generation: 0, realm: Realm.QiRefinement, subRealm: 5, age: 34, maxAge: 105,
        physique: '玄阴之智', aptitude: 82, comprehension: 96, divineSense: 48,
        roots: { gold: 8, wood: 0, water: 3, fire: 0, earth: 0 },
        rootGrade: '中品灵根', talents: { ...defaultTalents, 百艺天赋: { ...defaultTalents.百艺天赋, 阵法: 88 } },
        tier: '天才', element: Element.Water, status: 'healthy', loyalty: 100, assignment: 'Cultivation', legacyPoints: 40,
