        physique: '青穗剑仙', aptitude: 99, comprehension: 92, divineSense: 55,
        roots: { gold: 2, wood: 3, water: 10, fire: 5, earth: 2 },
        rootGrade: '极品灵根', talents: { ...defaultTalents, 战斗天赋: { ...defaultTalents.战斗天赋, 剑法: 99 } },
        tier: '绝世天骄', element: Element.Gold, status: 'healthy', loyalty: 100, assignment: 'Cultivation', legacyPoints: 60,
        mainMethodId: 'm1', movementMethodId: null, auxMethodIds: ['m8', 'm9'], cultivationProgress: 80, developmentPlan: 'Combat', divineAbilities: [], sect: '望月李氏', position: '寻常族子',
