import React, { useState, useEffect } from 'react';
import { GameState, ClanMember, Region, Realm, TaskType, Element, SpecializedTalents, ElementalRoots, TalentTier, RootGrade, DevelopmentPlan, CultivationMethod, Building, Item, ItemType } from './types';
import { INITIAL_MEMBERS, INITIAL_REGIONS, REALM_ORDER, GENERATIONS, SURNAMES, CULTIVATION_METHODS, ABILITIES, SECTS, POSITIONS, PHYSIQUES, BUILDING_TYPES, INITIAL_ITEMS } from './constants';
import ClanDashboard from './components/ClanDashboard';
import WorldMap from './components/WorldMap';
import ClanManagement from './components/ClanManagement';
import { generateYearlyEvent, consultHaotianMirror } from './services/geminiService';

const App: React.FC = () => {
    const [state, setState] = useState<GameState>({
        year: 1,
        spiritStones: 500,
        merit: 100,
        luck: 50,
        members: INITIAL_MEMBERS,
        regions: INITIAL_REGIONS,
        buildings: [],
        inventory: INITIAL_ITEMS,
        currentRegionId: '',
        isMirrorActive: false,
        logs: ["太平历初，望月李氏在此立基。"],
        heritagePool: 0,
    });

    const [event, setEvent] = useState<any>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isDashboardVisible, setIsDashboardVisible] = useState(true);
    const [isManagementVisible, setIsManagementVisible] = useState(false);
    const [isConsoleCollapsed, setIsConsoleCollapsed] = useState(false);

    const getRootGrade = (roots: ElementalRoots): RootGrade => {
        const vals = Object.values(roots);
        const activeCount = vals.filter(v => v > 0).length;
        const maxVal = Math.max(...vals);
        const highCount = vals.filter(v => v > 5).length;
        const veryHighCount = vals.filter(v => v > 6).length;

        if (activeCount === 0) return '凡胎';
        if (activeCount === 5 && (veryHighCount >= 3 || maxVal > 9)) return '极品灵根';
        if (activeCount >= 3 && (highCount >= 2 || maxVal > 7)) return '中品灵根';
        if (activeCount <= 2 && maxVal > 5) return '下品灵根';
        return '伪灵根'; 
    };

    const getOverallTier = (aptitude: number, rootGrade: RootGrade): TalentTier => {
        if (rootGrade === '凡胎') return '凡人';
        if (rootGrade === '伪灵根' && aptitude < 30) return '庸才';
        if (aptitude > 95 || (rootGrade === '极品灵根' && aptitude > 90)) return '绝世天骄';
        if (aptitude > 85 || rootGrade === '极品灵根') return '绝世';
        if (aptitude > 70 || rootGrade === '中品灵根') return '天才';
        if (aptitude > 50) return '超凡';
        if (aptitude > 30) return '普通';
        return '庸才';
    };

    const handleUpdateMember = (id: string, updates: Partial<ClanMember>) => {
        setState(prev => ({
            ...prev,
            members: prev.members.map(m => m.id === id ? { ...m, ...updates } : m)
        }));
    };

    const handleUpdateRegion = (id: string, updates: Partial<Region>) => {
        setState(prev => ({
            ...prev,
            regions: prev.regions.map(r => r.id === id ? { ...r, ...updates } : r)
        }));
    };

    const handleAddBuilding = (type: string) => {
        const info = (BUILDING_TYPES as any)[type];
        if (!info) return;
        if (state.spiritStones < info.baseCost) return;

        const newBuilding: Building = {
            id: `build-${Date.now()}`,
            type,
            level: 1,
            assignedMemberId: null
        };

        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones - info.baseCost,
            buildings: [...prev.buildings, newBuilding],
            logs: [`【营建】${info.name} 建造完成。`, ...prev.logs].slice(0, 15)
        }));
    };

    const handleAssignBuilding = (buildingId: string, memberId: string | null) => {
        setState(prev => ({
            ...prev,
            buildings: prev.buildings.map(b => b.id === buildingId ? { ...b, assignedMemberId: memberId } : b)
        }));
    };

    const handleEquipItem = (memberId: string, item: Item | null, slot: ItemType) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === memberId);
            if (!member) return prev;

            const newInventory = [...prev.inventory];
            const newEquipment = { ...member.equipment };

            // Unequip current item if any
            let currentItem: Item | null = null;
            if (slot === 'Weapon') { currentItem = newEquipment.weapon; newEquipment.weapon = item; }
            else if (slot === 'Armor') { currentItem = newEquipment.armor; newEquipment.armor = item; }
            else if (slot === 'Accessory') { currentItem = newEquipment.accessory; newEquipment.accessory = item; }
            else if (slot === 'Mount') { currentItem = newEquipment.mount; newEquipment.mount = item; }

            if (currentItem) newInventory.push(currentItem);

            // Remove newly equipped item from inventory
            if (item) {
                const idx = newInventory.findIndex(i => i.id === item.id);
                if (idx !== -1) newInventory.splice(idx, 1);
            }

            return {
                ...prev,
                inventory: newInventory,
                members: prev.members.map(m => m.id === memberId ? { ...m, equipment: newEquipment } : m),
                logs: [`【装备】${member.name} ${item ? '装备了' : '卸下了'} ${item ? item.name : (currentItem?.name || '物品')}。`, ...prev.logs].slice(0, 15)
            };
        });
    };

    const handleAddMember = () => {
        if (state.spiritStones < 100) {
            setState(p => ({ ...p, logs: ["灵石短缺，无力供养更多新丁。", ...p.logs].slice(0, 15) }));
            return;
        }

        const genIdx = Math.floor(state.year / 40) % GENERATIONS.length;
        const genPrefix = GENERATIONS[genIdx];
        const names = ['清', '锋', '明', '煌', '守', '信', '元', '载', '宏', '远', '志', '浩'];
        const randomName = names[Math.floor(Math.random() * names.length)];
        const gender = Math.random() > 0.5 ? '男' : '女';

        const rootRolls = {
            gold: Math.random() > 0.6 ? Math.floor(Math.random() * 10) + 1 : 0,
            wood: Math.random() > 0.6 ? Math.floor(Math.random() * 10) + 1 : 0,
            water: Math.random() > 0.6 ? Math.floor(Math.random() * 10) + 1 : 0,
            fire: Math.random() > 0.6 ? Math.floor(Math.random() * 10) + 1 : 0,
            earth: Math.random() > 0.6 ? Math.floor(Math.random() * 10) + 1 : 0,
        };

        const rootGrade = getRootGrade(rootRolls);
        const aptitude = 10 + Math.floor(Math.random() * 80) + (rootGrade === '极品灵根' ? 10 : 0);
        const comprehension = 20 + Math.floor(Math.random() * 70);
        const divineSense = 5 + Math.floor(Math.random() * 30);
        const tier = getOverallTier(aptitude, rootGrade);

        const talents: SpecializedTalents = {
            战斗天赋: {
                剑法: Math.floor(Math.random() * 60),拳法: Math.floor(Math.random() * 60),枪法: Math.floor(Math.random() * 60),刀法: Math.floor(Math.random() * 60),弓箭: Math.floor(Math.random() * 60),
            },
            百艺天赋: {
                炼丹: Math.floor(Math.random() * 60),炼器: Math.floor(Math.random() * 60),制符: Math.floor(Math.random() * 60),阵法: Math.floor(Math.random() * 60),
            }
        };

        const bornAbilities: string[] = [];
        if (tier === '绝世天骄' || tier === '绝世') {
            if (Math.random() < 0.2) {
                bornAbilities.push(ABILITIES[Math.floor(Math.random() * ABILITIES.length)]);
            }
        }

        const newMember: ClanMember = {
            id: `member-${Date.now()}-${Math.random()}`,
            name: `${SURNAMES[0]}${genPrefix}${randomName}`,
            gender: gender as '男' | '女',
            generation: genIdx,
            realm: Realm.QiRefinement,
            subRealm: 1,
            age: 8 + Math.floor(Math.random() * 10),
            maxAge: 75 + Math.floor(Math.random() * 45),
            physique: rootGrade === '凡胎' ? '凡人' : PHYSIQUES[Math.floor(Math.random() * PHYSIQUES.length)],
            aptitude, comprehension, divineSense, roots: rootRolls, rootGrade, talents, tier,
            element: [Element.Gold, Element.Wood, Element.Water, Element.Fire, Element.Earth][Math.floor(Math.random() * 5)],
            status: 'healthy', loyalty: 75 + Math.floor(Math.random() * 25), assignment: 'Idle', legacyPoints: 0,
            mainMethodId: rootGrade === '凡胎' ? null : 'm1', movementMethodId: null, auxMethodIds: [],
            cultivationProgress: 0, developmentPlan: 'Balanced', divineAbilities: bornAbilities, sect: '望月李氏', position: '寻常族子',
            equipment: { weapon: null, armor: null, accessory: null, mount: null }
        };

        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones - 100,
            members: [...prev.members, newMember],
            logs: [`【族讯】李氏子弟 ${newMember.name} 测得【${newMember.rootGrade}】。`, ...prev.logs].slice(0, 15)
        }));
    };

    const handleNextYear = async () => {
        setIsProcessing(true);
        let yearLogs: string[] = [];
        let stoneGain = 150; 
        let heritageGain = 0;
        let casualties: string[] = [];
        let injuredMemberIds: string[] = [];

        state.buildings.forEach(b => {
            const hasAssigned = !!b.assignedMemberId;
            if (b.type === 'Market' && hasAssigned) stoneGain += 100 * b.level;
            if (b.type === 'SpiritField') stoneGain += 50 * b.level;
            if (b.type === 'Library' && hasAssigned) heritageGain += 2 * b.level;
        });

        const updatedRegions = state.regions.map(region => {
            if (!region.activeMission) return region;
            const mission = region.activeMission;
            const turnsRemaining = mission.turnsRemaining - 1;
            if (turnsRemaining <= 0) {
                const member = state.members.find(m => m.id === mission.memberId);
                if (member) {
                    if (region.category === 'Natural') {
                        const gain = 50 + region.difficulty * 20 + Math.floor(Math.random() * 50);
                        stoneGain += gain;
                        yearLogs.push(`【派遣】${member.name} 完成 ${region.name} 巡视，带回灵石 ${gain}。`);
                    } else if (region.category === 'Mystic') {
                        const gain = 200 + region.difficulty * 50 + Math.floor(Math.random() * 150);
                        stoneGain += gain;
                        heritageGain += 10;
                        yearLogs.push(`【探险】${member.name} 从秘境 ${region.name} 归来，收获灵石 ${gain}。`);
                    }
                }
                return { ...region, activeMission: undefined };
            }
            return { ...region, activeMission: { ...mission, turnsRemaining } };
        });

        const updatedMembers: ClanMember[] = state.members.map(member => {
            if (member.status === 'dead') return member;
            let m: ClanMember = { ...member };
            m.age += 1;
            if (casualties.includes(m.id)) { m.status = 'dead'; m.deathYear = state.year; return m; }
            if (injuredMemberIds.includes(m.id)) { m.status = 'injured'; }

            if (m.assignment === 'Cultivation') {
                const luckFactor = 1 + (state.luck / 200); 
                const rootModifier = m.rootGrade === '极品灵根' ? 1.5 : m.rootGrade === '中品灵根' ? 1.2 : 1.0;
                m.cultivationProgress += (m.aptitude / 10) * luckFactor * rootModifier;
                if (m.cultivationProgress >= 100) {
                    m.cultivationProgress = 0;
                    if (m.subRealm < 9) { m.subRealm += 1; } 
                    else {
                        const currentIndex = REALM_ORDER.indexOf(m.realm);
                        if (currentIndex < REALM_ORDER.length - 1) {
                            const nextRealm = REALM_ORDER[currentIndex + 1];
                            m.realm = nextRealm; m.subRealm = 1; m.maxAge += (currentIndex + 2) * 50; 
                            yearLogs.push(`突破：${m.name} 晋升 ${m.realm}！`);
                            if (nextRealm === Realm.YuanYing && m.divineAbilities.length === 0) {
                                const randomAbility = ABILITIES[Math.floor(Math.random() * ABILITIES.length)];
                                m.divineAbilities.push(randomAbility);
                                yearLogs.push(`觉醒：${m.name} 证就元婴，觉醒神通【${randomAbility}】！`);
                            }
                        }
                    }
                }
            }

            if (m.age >= m.maxAge && m.status !== 'dead') { m.status = 'dead'; m.deathYear = state.year; yearLogs.push(`陨落：${m.name} 终年 ${m.age} 岁。`); }
            return m;
        });

        const newEvent = await generateYearlyEvent({ ...state, members: updatedMembers });
        setState(prev => ({
            ...prev,
            year: prev.year + 1,
            members: updatedMembers,
            regions: updatedRegions,
            spiritStones: prev.spiritStones + stoneGain,
            heritagePool: prev.heritagePool + heritageGain,
            logs: [...yearLogs, ...prev.logs].slice(0, 15)
        }));
        setEvent(newEvent);
        setIsProcessing(false);
    };

    const handleEventChoice = (choice: 'A' | 'B') => {
        if (!event) return;
        const impact = event.impact;
        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones + impact.spiritStones,
            merit: prev.merit + impact.merit,
            luck: Math.min(100, Math.max(0, prev.luck + impact.luck)),
            logs: [`【抉择】${impact.log}`, ...prev.logs].slice(0, 15),
        }));
        setEvent(null);
    };

    return (
        <div className="h-screen w-screen flex flex-col bg-[#0f0a07] text-gray-300 overflow-hidden select-none font-serif">
            <header className="h-16 bg-[#2c1810] border-b-2 border-yellow-900/50 flex items-center justify-between px-8 z-40 shadow-xl">
                <div className="flex items-center gap-12">
                    <div className="flex flex-col">
                        <h1 className="text-2xl font-cursive text-yellow-500 tracking-widest">玄鉴仙族：昊天纪元</h1>
                    </div>
                    <div className="flex gap-6 items-center border-l border-yellow-900/30 pl-8">
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase tracking-tighter">家族灵石</span>
                            <span className="text-lg font-mono text-yellow-400">✨ {state.spiritStones}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase tracking-tighter">天罡历载</span>
                            <span className="text-lg font-mono text-yellow-100">{state.year}</span>
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-4">
                    <button onClick={() => setIsManagementVisible(true)} className="px-5 py-2 bg-black/40 border border-orange-900 text-orange-500 rounded-full text-xs font-bold hover:bg-orange-900/20 transition-all">
                        🏛️ 家族管理
                    </button>
                    <button onClick={() => setIsDashboardVisible(!isDashboardVisible)} className={`px-5 py-2 rounded-full border transition-all text-xs font-bold flex items-center gap-2 ${isDashboardVisible ? 'bg-yellow-800 border-yellow-500 text-yellow-100' : 'bg-black/40 border-yellow-900 text-gray-500'}`}>
                        📜 族谱
                    </button>
                    <button onClick={handleNextYear} disabled={isProcessing || !!event} className="bg-gradient-to-b from-yellow-700 to-yellow-900 hover:from-yellow-600 hover:to-yellow-800 disabled:opacity-30 text-white px-8 py-2 rounded border-t border-yellow-500/30 border-b-4 border-black/50 font-bold transition-all text-sm shadow-lg">
                        {isProcessing ? '推演中' : '岁过一载'}
                    </button>
                </div>
            </header>

            <main className="flex-1 flex overflow-hidden">
                <div className="flex-1 relative bg-[#0a0705]">
                    <WorldMap 
                        regions={state.regions} 
                        members={state.members} 
                        currentRegionId={state.currentRegionId} 
                        onSelectRegion={(r) => {
                            if (r?.id === 'li_clan_home') {
                                setIsManagementVisible(true);
                                setState(p => ({ ...p, currentRegionId: '' }));
                            } else {
                                setState(p => ({ ...p, currentRegionId: r ? r.id : '' }));
                            }
                        }} 
                        onUpdateMember={handleUpdateMember} 
                        onUpdateRegion={handleUpdateRegion} 
                    />
                    <div className={`absolute bottom-6 left-6 transition-all duration-500 ease-in-out parchment border-2 border-[#4a3728] rounded-sm shadow-2xl z-20 opacity-95 ${isConsoleCollapsed ? 'w-48 h-10' : 'w-72 h-56'}`}>
                        <div className="flex justify-between items-center px-4 py-2 border-b border-[#4a3728]/30 bg-black/5">
                            <span className="text-[11px] text-[#2c1810] font-bold uppercase tracking-widest font-cursive">族史摘要</span>
                            <button onClick={() => setIsConsoleCollapsed(!isConsoleCollapsed)} className="text-[#4a3728] hover:text-black p-1">
                                <span className="text-lg leading-none">{isConsoleCollapsed ? '▲' : '▼'}</span>
                            </button>
                        </div>
                        {!isConsoleCollapsed && (
                            <div className="flex-1 overflow-y-auto p-4 pt-1 space-y-2.5 custom-scrollbar text-[11px]">
                                {state.logs.map((log, i) => (
                                    <p key={i} className="leading-relaxed text-black/80 font-serif font-bold tracking-tight">
                                        <span className="text-[#8b0000] mr-2">◈</span> {log}
                                    </p>
                                ))}
                            </div>
                        )}
                    </div>
                </div>
                {isDashboardVisible && (
                    <div className="w-80 h-full shadow-2xl z-30 animate-slide-left border-l border-yellow-900/50">
                        <ClanDashboard 
                            state={state} 
                            onUpdateMember={handleUpdateMember} 
                            onAddMember={handleAddMember} 
                            onEquipItem={handleEquipItem}
                        />
                    </div>
                )}
            </main>

            {isManagementVisible && (
                <ClanManagement 
                    state={state} 
                    onUpdateMember={handleUpdateMember} 
                    onAddBuilding={handleAddBuilding} 
                    onAssignBuilding={handleAssignBuilding} 
                    onClose={() => setIsManagementVisible(false)} 
                />
            )}

            {event && (
                <div className="fixed inset-0 z-50 flex items-start justify-center bg-black/80 backdrop-blur-sm p-4 pt-20 sm:pt-24 overflow-hidden">
                    <div className="bg-[#f4e4bc] w-full max-w-3xl max-h-[85vh] p-8 sm:p-12 rounded border-[14px] border-[#4a3728] shadow-2xl relative scroll-shadow flex flex-col">
                        <div className="absolute -top-10 left-1/2 -translate-x-1/2 bg-[#4a3728] text-yellow-500 px-10 sm:px-16 py-3 sm:py-4 rounded-b-xl font-cursive text-2xl sm:text-3xl z-10 whitespace-nowrap">{event.title}</div>
                        <div className="flex-1 overflow-y-auto custom-scrollbar mt-4 pr-4">
                            <div className="text-[#2c1810] leading-relaxed text-xl sm:text-2xl font-serif italic opacity-90 indent-12">{event.content}</div>
                        </div>
                        <div className="mt-8 grid grid-cols-1 sm:grid-cols-2 gap-4 sm:gap-8 relative z-10 shrink-0">
                            <button onClick={() => handleEventChoice('A')} className="group p-4 sm:p-6 border-2 border-[#4a3728]/40 rounded-xl hover:bg-[#4a3728] transition-all text-left">
                                <p className="font-bold text-base sm:text-lg text-[#2c1810] group-hover:text-yellow-400">◈ {event.choiceA.text}</p>
                                <p className="text-[10px] sm:text-xs text-[#2c1810]/60 group-hover:text-yellow-100/60">{event.choiceA.effect}</p>
                            </button>
                            <button onClick={() => handleEventChoice('B')} className="group p-4 sm:p-6 border-2 border-[#4a3728]/40 rounded-xl hover:bg-[#4a3728] transition-all text-left">
                                <p className="font-bold text-base sm:text-lg text-[#2c1810] group-hover:text-yellow-400">◈ {event.choiceB.text}</p>
                                <p className="text-[10px] sm:text-xs text-[#2c1810]/60 group-hover:text-yellow-100/60">{event.choiceB.effect}</p>
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

