import React, { useState } from 'react';
import { GameState, ClanMember, Building, Realm } from '../types';
import { BUILDING_TYPES, POSITIONS, REALM_ORDER } from '../constants';

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddBuilding: (type: string) => void;
    onAssignBuilding: (buildingId: string, memberId: string | null) => void;
    onClose: () => void;
}

const ClanManagement: React.FC<Props> = ({ state, onUpdateMember, onAddBuilding, onAssignBuilding, onClose }) => {
    const [tab, setTab] = useState<'buildings' | 'positions'>('buildings');

    const aliveMembers = state.members.filter(m => m.status !== 'dead');

    const checkRequirements = (type: string, level: number) => {
        const info = (BUILDING_TYPES as any)[type];
        const levelInfo = info.levels[level - 1];
        if (!levelInfo) return { met: false, reason: "已达最高等级" };

        const realmIdx = REALM_ORDER.indexOf(levelInfo.reqRealm);

        // 检查是否有任何族人满足境界要求
        const hasRealm = aliveMembers.some(m => REALM_ORDER.indexOf(m.realm) >= realmIdx);
        if (!hasRealm) return { met: false, reason: `需至少一人达到${levelInfo.reqRealm}期` };

        // 检查是否有任何族人满足百艺天赋要求
        if (levelInfo.reqTalent) {
            const hasTalent = aliveMembers.some(m => {
                const talentType = levelInfo.reqTalent.type;
                const talentValue = (m.talents.百艺天赋 as any)[talentType];
                return talentValue >= levelInfo.reqTalent.value;
            });
            if (!hasTalent) return { met: false, reason: `需至少一名${levelInfo.reqTalent.value}级${levelInfo.reqTalent.type}师` };
        }

        return { met: true, reason: "" };
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md p-4 font-serif overflow-hidden">
            <div className="relative w-full max-w-6xl h-[90vh] bg-[#1a1310] border-[8px] border-[#4a3728] rounded shadow-2xl flex flex-col">
                {/* Header */}
                <div className="h-16 bg-[#2c1810] border-b border-yellow-900/30 flex items-center px-8 shrink-0">
                    <h2 className="text-2xl font-cursive text-yellow-500 mr-12">🏯 家族大社</h2>
                    <div className="flex gap-4">
                        <button onClick={() => setTab('buildings')} className={`px-4 py-1 text-sm border-b-2 transition-all ${tab === 'buildings' ? 'border-yellow-500 text-yellow-500' : 'border-transparent text-gray-500'}`}>建筑营造</button>
                        <button onClick={() => setTab('positions')} className={`px-4 py-1 text-sm border-b-2 transition-all ${tab === 'positions' ? 'border-yellow-500 text-yellow-500' : 'border-transparent text-gray-500'}`}>职位册封</button>
                    </div>
                    <button onClick={onClose} className="ml-auto w-10 h-10 bg-red-900/20 hover:bg-red-900/40 text-red-500 rounded-full flex items-center justify-center text-2xl transition-all">×</button>
                </div>

                <div className="flex-1 overflow-hidden flex flex-col p-6">
                    {tab === 'buildings' ? (
                        <div className="flex-1 flex gap-6 overflow-hidden">
                            {/* Building List */}
                            <div className="flex-1 overflow-y-auto pr-4 space-y-4 custom-scrollbar">
                                <h3 className="text-yellow-600 font-bold border-b border-yellow-900/20 pb-2 mb-4">已有建筑</h3>
                                {state.buildings.length > 0 ? (
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        {state.buildings.map(b => {
                                            const typeInfo = (BUILDING_TYPES as any)[b.type];
                                            const assignedMember = state.members.find(m => m.id === b.assignedMemberId);
                                            return (
                                                <div key={b.id} className="bg-black/30 border border-yellow-900/10 p-4 rounded-lg flex flex-col gap-3 relative overflow-hidden">
                                                    {b.isConstructing && (
                                                        <div className="absolute inset-0 bg-black/60 z-10 flex flex-col items-center justify-center p-6 text-center">
                                                            <div className="text-yellow-500 font-bold text-sm mb-2 animate-pulse">正在营建中...</div>
                                                            <div className="w-full bg-gray-900 h-2 rounded-full overflow-hidden mb-1">
                                                                <div 
                                                                    className="bg-yellow-600 h-full transition-all duration-500" 
                                                                    style={{ width: `${((b.totalConstructionTime - b.remainingTurns) / b.totalConstructionTime) * 100}%` }}
                                                                />
                                                            </div>
                                                            <div className="text-[10px] text-gray-400">预计还需 {b.remainingTurns} 年</div>
                                                        </div>
                                                    )}

                                                    <div className="flex justify-between items-center">
                                                        <div className="flex items-center gap-2">
                                                            <span className="text-2xl">{typeInfo.icon}</span>
                                                            <span className="font-bold text-yellow-100">{typeInfo.name} <span className="text-[10px] text-yellow-800">等级 {b.level}</span></span>
                                                        </div>
                                                        <button 
                                                            onClick={() => onAddBuilding(b.type)}
                                                            disabled={b.isConstructing || !checkRequirements(b.type, b.level + 1).met}
                                                            className={`px-3 py-1 text-[10px] rounded transition-all ${b.isConstructing ? 'bg-gray-800 text-gray-500' : 'bg-yellow-900/40 text-yellow-500 hover:bg-yellow-700 hover:text-white border border-yellow-900/30'}`}
                                                        >
                                                            升级
                                                        </button>
                                                    </div>
                                                    <p className="text-[11px] text-gray-500">{typeInfo.desc}</p>
                                                    <div className="mt-auto pt-3 border-t border-white/5 flex flex-col gap-2">
                                                        <span className="text-[10px] text-gray-400">派驻执事:</span>
                                                        <select 
                                                            className="bg-[#2c1810] text-[11px] text-yellow-500 border border-yellow-900/30 p-1 rounded w-full outline-none"
                                                            value={b.assignedMemberId || ''}
                                                            onChange={(e) => onAssignBuilding(b.id, e.target.value || null)}
                                                        >
                                                            <option value="">- 无 -</option>
                                                            {aliveMembers.map(m => (
                                                                <option key={m.id} value={m.id}>{m.name} ({m.realm})</option>
                                                            ))}
                                                        </select>
                                                    </div>
                                                </div>
                                            );
                                        })}
                                    </div>
                                ) : (
                                    <p className="text-center py-20 text-gray-700 italic">尚未兴建任何家族设施</p>
                                )}
                            </div>

                            {/* Build New */}
                            <div className="w-80 bg-black/40 border border-yellow-900/20 p-4 rounded flex flex-col shrink-0 overflow-y-auto custom-scrollbar">
                                <h3 className="text-yellow-600 font-bold border-b border-yellow-900/20 pb-2 mb-4">营造所</h3>
                                <div className="space-y-3">
                                    {Object.entries(BUILDING_TYPES).map(([type, info]) => {
                                        const building = state.buildings.find(b => b.type === type);
                                        const alreadyBuilt = !!building;
                                        const nextLevel = alreadyBuilt ? building.level + 1 : 1;
                                        const req = checkRequirements(type, nextLevel);
                                        const cost = info.baseCost * nextLevel;

                                        return (
                                            <div key={type} className="bg-[#2c1810]/40 p-3 rounded border border-yellow-900/10 group relative">
                                                <div className="flex justify-between items-center mb-1">
                                                    <span className="font-bold text-sm text-yellow-100">{info.icon} {info.name}</span>
                                                    <span className="text-[10px] text-yellow-600">✨ {cost}</span>
                                                </div>
                                                <p className="text-[10px] text-gray-500 mb-2">{info.desc}</p>

                                                <div className="mb-2 p-1.5 bg-black/40 rounded border border-white/5 space-y-1">
                                                    <div className="text-[9px] text-gray-500">下一级需求:</div>
                                                    <div className={`text-[9px] ${state.members.some(m => REALM_ORDER.indexOf(m.realm) >= REALM_ORDER.indexOf(info.levels[nextLevel-1]?.reqRealm)) ? 'text-green-600' : 'text-red-800'}`}>
                                                        • 境界: {info.levels[nextLevel-1]?.reqRealm}
                                                    </div>
                                                    {info.levels[nextLevel-1]?.reqTalent && (
                                                        <div className={`text-[9px] ${state.members.some(m => (m.talents.百艺天赋 as any)[info.levels[nextLevel-1].reqTalent.type] >= info.levels[nextLevel-1].reqTalent.value) ? 'text-green-600' : 'text-red-800'}`}>
                                                            • 百艺: {info.levels[nextLevel-1].reqTalent.value}级{info.levels[nextLevel-1].reqTalent.type}师
                                                        </div>
                                                    )}
                                                    <div className="text-[9px] text-blue-800">• 工期: {info.levels[nextLevel-1]?.time} 载</div>
                                                </div>

                                                <button 
                                                    onClick={() => onAddBuilding(type)}
                                                    disabled={alreadyBuilt || !req.met || state.spiritStones < cost}
                                                    className={`w-full py-1.5 rounded text-[10px] font-bold transition-all ${alreadyBuilt ? 'bg-gray-800 text-gray-600 cursor-default' : req.met ? 'bg-yellow-900/20 hover:bg-yellow-700 text-yellow-500 hover:text-white border border-yellow-900/30' : 'bg-red-900/10 text-red-900 border border-red-900/20 cursor-not-allowed'}`}
                                                >
                                                    {alreadyBuilt ? '已兴建' : req.met ? '点击营造' : req.reason}
                                                </button>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        </div>
                    ) : (
                        <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar">
                            <h3 className="text-yellow-600 font-bold border-b border-yellow-900/20 pb-2 mb-4">职位分配</h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                                {aliveMembers.map(m => (
                                    <div key={m.id} className="bg-black/30 border border-yellow-900/10 p-3 rounded flex justify-between items-center">
                                        <div className="flex flex-col">
                                            <span className="text-sm font-bold text-yellow-100">{m.name}</span>
                                            <span className="text-[10px] text-gray-500">{m.realm}{m.subRealm}层</span>
                                        </div>
                                        <select 
                                            className="bg-[#2c1810] text-[11px] text-orange-400 border border-yellow-900/30 p-1.5 rounded outline-none"
                                            value={m.position}
                                            onChange={(e) => onUpdateMember(m.id, { position: e.target.value })}
                                        >
                                            {POSITIONS.map(p => (
                                                <option key={p} value={p}>{p}</option>
                                            ))}
                                        </select>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>

                <div className="h-10 bg-black/60 border-t border-yellow-900/20 flex items-center px-8 text-[10px] text-gray-600 gap-6 shrink-0">
                    <span>家族灵石: <span className="text-yellow-500">{state.spiritStones}</span></span>
                    <span>派驻比例: <span className="text-blue-500">{state.buildings.filter(b => !!b.assignedMemberId).length} / {state.buildings.length}</span></span>
                </div>
            </div>
        </div>
    );
};

