export type MethodQuality = '上等' | '中等' | '下等';
export type MethodType = 'Cultivation' | 'Combat' | 'Movement';

export type ItemType = 'Weapon' | 'Armor' | 'Accessory' | 'Mount' | 'Pill' | 'Material' | 'Talisman' | 'Recipe';

export interface Item {
    id: string;
    name: string;
    type: ItemType;
    grade: number;
    quality: MethodQuality;
    desc: string;
    amount?: number; // 堆叠数量
    buffs: {
        attack?: number;
        defense?: number;
        health?: number;
        speed?: number;
        successRate?: number;
    };
}

export interface Recipe {
    pillId: string;
    name: string;
    ingredients: { itemId: string; amount: number }[];
    reqLevel: number;
    reqTalentType: '炼丹' | '炼器' | '制符';
    desc: string;
}

export interface Building {
    id: string;
    type: string;
    level: number;
    assignedMemberId: string | null;
    isConstructing: boolean;
    remainingTurns: number;
    totalConstructionTime: number;
}

export interface MethodBuffs {
    cultivationSpeed?: number;
    attack?: number;
    defense?: number;
    divineSense?: number;
    maxAge?: number;
}

export interface CultivationMethod {
    id: string;
    name: string;
    grade: number;
    quality: MethodQuality;
    type: MethodType;
    element: Element | '无';
    desc: string;
    bonus: string;
    buffs: MethodBuffs;
}

export interface ElementalRoots {
    gold: number;
    wood: number;
    water: number;
    fire: number;
    earth: number;
}

export interface SpecializedTalents {
    战斗天赋: {
        剑法: number;
        拳法: number;
        枪法: number;
        刀法: number;
        弓箭: number;
    };
    百艺天赋: {
        炼丹: number;
        炼器: number;
        制符: number;
        阵法: number;
    };
}

export interface ClanMember {
    id: string;
    name: string;
    gender: '男' | '女';
    generation: number; 
    realm: Realm;
    subRealm: number; 
    age: number;
    maxAge: number;
    physique: string;
    aptitude: number;
    comprehension: number;
    divineSense: number;
    roots: ElementalRoots;
    rootGrade: RootGrade;
    talents: SpecializedTalents;
    tier: TalentTier;

    element: Element;
    status: 'healthy' | 'injured' | 'dead';
    loyalty: number; 
    assignment: TaskType;
    legacyPoints: number; 
    deathYear?: number;

    mainMethodId: string | null;
    movementMethodId: string | null;
    auxMethodIds: string[];
    cultivationProgress: number;
    developmentPlan: DevelopmentPlan;
    divineAbilities: string[];
    sect: string;
    position: string;

    equipment: {
        weapon: Item | null;
        armor: Item | null;
        accessory: Item | null;
        mount: Item | null;
    };
}

