import React, { useState } from 'react';
import { GameState, ClanMember, Building, Realm, Item } from '../types';
import { BUILDING_TYPES, POSITIONS, REALM_ORDER, ALCHEMY_RECIPES } from '../constants';

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddBuilding: (type: string) => void;
    onAssignBuilding: (buildingId: string, memberId: string | null) => void;
    onClose: () => void;
}

const ClanManagement: React.FC<Props> = ({ state, onUpdateMember, onAddBuilding, onAssignBuilding, onClose }) => {
    const [tab, setTab] = useState<'overview' | 'buildings' | 'positions' | 'alchemy' | 'smithing' | 'talisman'>('overview');

    const aliveMembers = state.members.filter(m => m.status !== 'dead');

    // 计算各境界人数分布
    const realmDistribution = REALM_ORDER.reduce((acc, realm) => {
        acc[realm] = aliveMembers.filter(m => m.realm === realm).length;
        return acc;
    }, {} as Record<string, number>);

    // 获取已建成的功能建筑（且非营建中）
    const builtFunctionalBuildings = state.buildings.filter(b => !b.isConstructing && (BUILDING_TYPES as any)[b.type].category === 'Functional');

    const checkRequirements = (type: string, level: number) => {
        const info = (BUILDING_TYPES as any)[type];
        if (!info) return { met: false, reason: "未知建筑" };
        const levelInfo = info.levels[level - 1];
        if (!levelInfo) return { met: false, reason: "已达最高等级" };

        const realmIdx = REALM_ORDER.indexOf(levelInfo.reqRealm);
        const hasRealm = aliveMembers.some(m => REALM_ORDER.indexOf(m.realm) >= realmIdx);
        if (!hasRealm) return { met: false, reason: `需至少一人达到${levelInfo.reqRealm}期` };

        if (levelInfo.reqTalent) {
            const hasTalent = aliveMembers.some(m => {
                const talentType = levelInfo.reqTalent.type;
                const talentValue = (m.talents.百艺天赋 as any)[talentType];
                return talentValue >= levelInfo.reqTalent.value;
            });
            if (!hasTalent) return { met: false, reason: `需${levelInfo.reqTalent.value}级${levelInfo.reqTalent.type}师` };
        }

        return { met: true, reason: "" };
    };

    const renderBuildingCard = (b: Building) => {
        const typeInfo = (BUILDING_TYPES as any)[b.type];
        const req = checkRequirements(b.type, b.level + 1);
        return (
            <div key={b.id} className="bg-black/30 border border-yellow-900/10 p-4 rounded-lg flex flex-col gap-3 relative overflow-hidden">
                {b.isConstructing && (
                    <div className="absolute inset-0 bg-black/70 z-10 flex flex-col items-center justify-center p-6 text-center">
                        <div className="text-yellow-500 font-bold text-sm mb-2 animate-pulse">营建中...</div>
                        <div className="w-full bg-gray-900 h-1.5 rounded-full overflow-hidden mb-1">
                            <div 
                                className="bg-yellow-600 h-full transition-all duration-500" 
                                style={{ width: `${((b.totalConstructionTime - b.remainingTurns) / b.totalConstructionTime) * 100}%` }}
                            />
                        </div>
                        <div className="text-[9px] text-gray-400">还需 {b.remainingTurns} 年</div>
                    </div>
                )}

                <div className="flex justify-between items-center">
                    <div className="flex items-center gap-2">
                        <span className="text-xl">{typeInfo.icon}</span>
                        <span className="font-bold text-yellow-100 text-xs">{typeInfo.name} <span className="text-[10px] text-yellow-800">Lv.{b.level}</span></span>
                    </div>
                    <button 
                        onClick={() => onAddBuilding(b.type)}
                        disabled={b.isConstructing || !req.met}
                        className={`px-2 py-0.5 text-[9px] rounded transition-all ${b.isConstructing ? 'bg-gray-800 text-gray-500' : 'bg-yellow-900/40 text-yellow-500 hover:bg-yellow-700 hover:text-white border border-yellow-900/30'}`}
                    >
                        {req.met ? '升级' : '限制'}
                    </button>
                </div>
                <p className="text-[10px] text-gray-500 leading-tight h-8 overflow-hidden">{typeInfo.desc}</p>
                <div className="mt-auto pt-2 border-t border-white/5 flex flex-col gap-1">
                    <span className="text-[9px] text-gray-500">派驻执事:</span>
                    <select 
                        className="bg-[#2c1810] text-[10px] text-yellow-500 border border-yellow-900/20 p-1 rounded outline-none"
                        value={b.assignedMemberId || ''}
                        onChange={(e) => onAssignBuilding(b.id, e.target.value || null)}
                    >
                        <option value="">- 空位 -</option>
                        {aliveMembers.map(m => (
                            <option key={m.id} value={m.id}>{m.name} ({m.realm})</option>
                        ))}
                    </select>
                </div>
            </div>
        );
    };

    const renderConstructionOption = (type: string, info: any) => {
        const building = state.buildings.find(b => b.type === type);
        if (building) return null;
        const req = checkRequirements(type, 1);
        const cost = info.baseCost;

        return (
            <div key={type} className="bg-[#2c1810]/40 p-3 rounded border border-yellow-900/10 group flex flex-col">
                <div className="flex justify-between items-center mb-1">
                    <span className="font-bold text-xs text-yellow-100">{info.icon} {info.name}</span>
                    <span className="text-[9px] text-yellow-600">✨ {cost}</span>
                </div>
                <p className="text-[9px] text-gray-500 mb-2 leading-relaxed">{info.desc}</p>

                <div className="mb-2 p-1 bg-black/20 rounded border border-white/5 space-y-0.5">
                    <div className={`text-[8px] ${state.members.some(m => REALM_ORDER.indexOf(m.realm) >= REALM_ORDER.indexOf(info.levels[0].reqRealm)) ? 'text-green-700' : 'text-red-900'}`}>
                        • 境界: {info.levels[0].reqRealm}
                    </div>
                    {info.levels[0].reqTalent && (
                        <div className={`text-[8px] ${state.members.some(m => (m.talents.百艺天赋 as any)[info.levels[0].reqTalent.type] >= info.levels[0].reqTalent.value) ? 'text-green-700' : 'text-red-900'}`}>
                            • {info.levels[0].reqTalent.type}: {info.levels[0].reqTalent.value}
                        </div>
                    )}
                </div>

                <button 
                    onClick={() => onAddBuilding(type)}
                    disabled={!req.met || state.spiritStones < cost}
                    className={`mt-auto w-full py-1 rounded text-[10px] font-bold transition-all ${req.met ? 'bg-yellow-900/20 hover:bg-yellow-700 text-yellow-500 hover:text-white border border-yellow-900/30' : 'bg-red-900/10 text-red-900 border border-red-900/20 cursor-not-allowed opacity-50'}`}
                >
                    {req.met ? '建造' : '条件不足'}
                </button>
            </div>
        );
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md p-4 font-serif overflow-hidden">
            <div className="relative w-full max-w-7xl h-[92vh] bg-[#1a1310] border-[10px] border-[#4a3728] rounded-sm shadow-2xl flex flex-col">
                {/* 侧边导航栏 */}
                <div className="flex h-full overflow-hidden">
                    <div className="w-48 bg-[#2c1810] border-r border-yellow-900/30 flex flex-col p-4 gap-2">
                        <h2 className="text-xl font-cursive text-yellow-500 mb-6 text-center border-b border-yellow-900/20 pb-4">望月李氏</h2>

                        <button onClick={() => setTab('overview')} className={`px-4 py-3 text-xs text-left rounded transition-all font-bold ${tab === 'overview' ? 'bg-yellow-900/40 text-yellow-400 border border-yellow-900/30 shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}>🏠 家族概况</button>
                        <button onClick={() => setTab('buildings')} className={`px-4 py-3 text-xs text-left rounded transition-all font-bold ${tab === 'buildings' ? 'bg-yellow-900/40 text-yellow-400 border border-yellow-900/30' : 'text-gray-500 hover:text-gray-300'}`}>🏗️ 营建布局</button>
                        <button onClick={() => setTab('positions')} className={`px-4 py-3 text-xs text-left rounded transition-all font-bold ${tab === 'positions' ? 'bg-yellow-900/40 text-yellow-400 border border-yellow-900/30' : 'text-gray-500 hover:text-gray-300'}`}>🎖️ 名分册封</button>

                        <div className="mt-6 pt-4 border-t border-yellow-900/10">
                            <p className="text-[9px] text-yellow-900 font-bold mb-3 uppercase tracking-widest">族产工坊</p>
                            {builtFunctionalBuildings.map(b => (
                                <button 
                                    key={b.id} 
                                    onClick={() => setTab((BUILDING_TYPES as any)[b.type].tab.toLowerCase() as any)} 
                                    className={`w-full px-4 py-3 text-xs text-left rounded transition-all font-bold mb-1 ${tab === (BUILDING_TYPES as any)[b.type].tab.toLowerCase() ? 'bg-blue-900/20 text-blue-400 border border-blue-900/30' : 'text-gray-600 hover:text-gray-400'}`}
                                >
                                    {(BUILDING_TYPES as any)[b.type].icon} {(BUILDING_TYPES as any)[b.type].name}
                                </button>
                            ))}
                        </div>
                    </div>

                    <div className="flex-1 flex flex-col overflow-hidden bg-black/20">
                        {/* 顶栏 */}
                        <div className="h-16 border-b border-yellow-900/20 flex items-center px-8 justify-between shrink-0">
                            <h3 className="text-yellow-500 font-cursive text-xl">
                                {tab === 'overview' && '家族宗谱 · 灵气分布'}
                                {tab === 'buildings' && '万丈高楼 · 营建所'}
                                {tab === 'positions' && '嫡庶有序 · 册封名号'}
                                {tab === 'alchemy' && '丹鼎之道 · 炼丹工坊'}
                            </h3>
                            <button onClick={onClose} className="w-10 h-10 bg-red-900/10 hover:bg-red-900/30 text-red-500 rounded-full flex items-center justify-center text-2xl transition-all">×</button>
                        </div>

                        {/* 内容区 */}
                        <div className="flex-1 overflow-hidden">
                            {tab === 'overview' && (
                                <div className="p-8 h-full overflow-y-auto custom-scrollbar">
                                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                                        {/* 家族名片 */}
                                        <div className="lg:col-span-1 bg-black/40 border border-yellow-900/20 p-6 rounded-xl space-y-6">
                                            <div className="text-center">
                                                <div className="w-24 h-24 bg-yellow-900/10 border-2 border-yellow-700/30 rounded-full mx-auto flex items-center justify-center mb-4">
                                                    <span className="text-4xl text-yellow-600 font-cursive">李</span>
                                                </div>
                                                <h4 className="text-2xl text-yellow-500 font-cursive">望月李氏</h4>
