                                    </div>

                                    <div className="w-80 border-l border-yellow-900/20 bg-black/30 p-6 overflow-y-auto custom-scrollbar">
                                        <h3 className="text-yellow-700 font-bold border-b border-yellow-900/20 pb-2 mb-6 text-sm">建造面板</h3>
                                        <div className="space-y-4">
                                            {Object.entries(BUILDING_TYPES).map(([type, info]) => renderConstructionOption(type, info))}
                                        </div>
                                    </div>
                                </div>
                            )}

                            {tab === 'positions' && (
                                <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
                                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                                        {aliveMembers.map(m => (
                                            <div key={m.id} className="bg-black/30 border border-yellow-900/10 p-4 rounded-lg flex flex-col gap-3 shadow-inner">
                                                <div className="flex justify-between items-start">
                                                    <div className="flex flex-col">
                                                        <span className="text-sm font-bold text-yellow-100">{m.name}</span>
                                                        <span className="text-[10px] text-gray-500 font-sans">{m.realm}{m.subRealm}层</span>
                                                    </div>
                                                    <span className="text-[9px] bg-yellow-900/20 text-yellow-600 px-1.5 py-0.5 rounded border border-yellow-900/30 font-bold">{m.tier}</span>
                                                </div>
                                                <div className="space-y-1 mt-2">
                                                    <p className="text-[9px] text-gray-600">当前授职:</p>
                                                    <select className="bg-[#2c1810] text-[11px] text-orange-400 border border-yellow-900/20 p-2 rounded outline-none w-full font-bold" value={m.position} onChange={(e) => onUpdateMember(m.id, { position: e.target.value })}>
                                                        {POSITIONS.map(p => <option key={p} value={p}>{p}</option>)}
                                                    </select>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {tab === 'alchemy' && (
                                <div className="flex h-full overflow-hidden">
                                    {/* 炼丹室人员与进度 */}
                                    <div className="flex-1 p-8 overflow-y-auto custom-scrollbar bg-black/10">
                                        <div className="flex justify-between items-end mb-8">
                                            <div>
                                                <h4 className="text-yellow-600 font-bold mb-1">派驻炼丹师</h4>
                                                <div className="flex gap-4">
                                                    {state.buildings.filter(b => b.type === 'AlchemyRoom').map(b => {
                                                        const m = state.members.find(mem => mem.id === b.assignedMemberId);
                                                        return (
                                                            <div key={b.id} className="bg-black/40 border border-yellow-900/20 p-4 rounded-lg min-w-[200px]">
                                                                {m ? (
                                                                    <div className="flex items-center gap-3">
                                                                        <div className="w-10 h-10 bg-yellow-900/20 rounded-full flex items-center justify-center text-lg">👨‍🔬</div>
                                                                        <div>
                                                                            <p className="text-sm font-bold text-yellow-100">{m.name}</p>
                                                                            <p className="text-[10px] text-gray-500">炼丹造诣: {Math.floor(m.talents.百艺天赋.炼丹)}</p>
                                                                        </div>
                                                                    </div>
                                                                ) : (
                                                                    <p className="text-xs text-gray-700 italic">暂无派驻人员</p>
                                                                )}
                                                            </div>
                                                        );
                                                    })}
                                                </div>
                                            </div>
                                        </div>

                                        <h4 className="text-yellow-600 font-bold mb-4 border-b border-yellow-900/10 pb-2">可选丹方</h4>
                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                            {ALCHEMY_RECIPES.map(recipe => (
                                                <div key={recipe.pillId} className="bg-[#2c1810]/40 border border-yellow-900/10 p-4 rounded-lg flex flex-col gap-2">
                                                    <div className="flex justify-between items-center">
                                                        <span className="text-yellow-400 font-bold text-sm">💊 {recipe.name}</span>
                                                        <span className="text-[9px] text-gray-600">需求: {recipe.reqLevel}品</span>
                                                    </div>
                                                    <p className="text-[10px] text-gray-500 italic mb-2">{recipe.desc}</p>
                                                    <div className="flex flex-wrap gap-2">
                                                        {recipe.ingredients.map(ing => {
                                                            const invItem = state.inventory.find(i => i.id === ing.itemId);
                                                            const hasEnough = (invItem?.amount || 0) >= ing.amount;
                                                            return (
                                                                <span key={ing.itemId} className={`text-[9px] px-2 py-0.5 rounded border ${hasEnough ? 'border-green-900/30 text-green-700 bg-green-900/5' : 'border-red-900/30 text-red-900 bg-red-900/5'}`}>
                                                                    {invItem?.name || '未知'}: {ing.amount} (库: {invItem?.amount || 0})
                                                                </span>
                                                            );
                                                        })}
                                                    </div>
                                                    <button className="mt-4 w-full py-1.5 bg-yellow-900/20 text-yellow-600 border border-yellow-900/30 rounded text-[10px] font-bold hover:bg-yellow-700 hover:text-white transition-all">开炉炼制</button>
                                                </div>
                                            ))}
                                        </div>
                                    </div>

                                    {/* 右侧材料库 */}
                                    <div className="w-80 border-l border-yellow-900/20 bg-black/40 p-6 flex flex-col">
                                        <h4 className="text-yellow-700 font-bold text-sm border-b border-yellow-900/20 pb-2 mb-6">灵药仓库</h4>
                                        <div className="flex-1 overflow-y-auto custom-scrollbar space-y-2">
                                            {state.inventory.filter(i => i.type === 'Material').length > 0 ? (
                                                state.inventory.filter(i => i.type === 'Material').map(item => (
                                                    <div key={item.id} className="bg-black/30 border border-white/5 p-3 rounded flex justify-between items-center group">
                                                        <div>
                                                            <p className="text-xs font-bold text-gray-200">{item.name}</p>
                                                            <p className="text-[9px] text-gray-500 italic">{item.desc}</p>
                                                        </div>
                                                        <span className="text-yellow-600 font-mono text-sm">x{item.amount}</span>
                                                    </div>
                                                ))
                                            ) : (
                                                <p className="text-center py-20 text-gray-700 italic text-xs">尚无任何原材料</p>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                <div className="h-10 bg-black/60 border-t border-yellow-900/20 flex items-center px-8 text-[10px] text-gray-600 gap-8 shrink-0 tracking-widest">
                    <span>家族底蕴: <span className="text-blue-500">{state.heritagePool}</span></span>
                    <span>库存灵石: <span className="text-yellow-500">{state.spiritStones}</span></span>
                    <span>库存材料: <span className="text-green-600">{state.inventory.filter(i => i.type === 'Material').length} 种</span></span>
                </div>
            </div>
        </div>
    );
};

export default ClanManagement;

import React, { useState } from 'react';
import { GameState, ClanMember, Building, Realm, Item } from '../types';
import { BUILDING_TYPES, POSITIONS, REALM_ORDER, ALCHEMY_RECIPES } from '../constants';

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddBuilding: (type: string) => void;
    onAssignBuilding: (buildingId: string, memberId: string | null) => void;
    onClose: () => void;
}

const ClanManagement: React.FC<Props> = ({ state, onUpdateMember, onAddBuilding, onAssignBuilding, onClose }) => {
    const [tab, setTab] = useState<'overview' | 'buildings' | 'positions' | 'alchemy' | 'smithing' | 'talisman'>('overview');

    const aliveMembers = state.members.filter(m => m.status !== 'dead');

    // 计算各境界人数分布
    const realmDistribution = REALM_ORDER.reduce((acc, realm) => {
        acc[realm] = aliveMembers.filter(m => m.realm === realm).length;
        return acc;
    }, {} as Record<string, number>);

    // 获取已建成的功能建筑（且非营建中）
    const builtFunctionalBuildings = state.buildings.filter(b => !b.isConstructing && (BUILDING_TYPES as any)[b.type].category === 'Functional');

    const checkRequirements = (type: string, level: number) => {
        const info = (BUILDING_TYPES as any)[type];
        if (!info) return { met: false, reason: "未知建筑" };
        const levelInfo = info.levels[level - 1];
        if (!levelInfo) return { met: false, reason: "已达最高等级" };

        const realmIdx = REALM_ORDER.indexOf(levelInfo.reqRealm);
        const hasRealm = aliveMembers.some(m => REALM_ORDER.indexOf(m.realm) >= realmIdx);
        if (!hasRealm) return { met: false, reason: `需至少一人达到${levelInfo.reqRealm}期` };

        if (levelInfo.reqTalent) {
            const hasTalent = aliveMembers.some(m => {
                const talentType = levelInfo.reqTalent.type;
                const talentValue = (m.talents.百艺天赋 as any)[talentType];
                return talentValue >= levelInfo.reqTalent.value;
            });
            if (!hasTalent) return { met: false, reason: `需${levelInfo.reqTalent.value}级${levelInfo.reqTalent.type}师` };
        }

        return { met: true, reason: "" };
    };

    const renderBuildingCard = (b: Building) => {
        const typeInfo = (BUILDING_TYPES as any)[b.type];
        const req = checkRequirements(b.type, b.level + 1);
        return (
            <div key={b.id} className="bg-black/30 border border-yellow-900/10 p-4 rounded-lg flex flex-col gap-3 relative overflow-hidden">
                {b.isConstructing && (
                    <div className="absolute inset-0 bg-black/70 z-10 flex flex-col items-center justify-center p-6 text-center">
                        <div className="text-yellow-500 font-bold text-sm mb-2 animate-pulse">营建中...</div>
                        <div className="w-full bg-gray-900 h-1.5 rounded-full overflow-hidden mb-1">
                            <div 
                                className="bg-yellow-600 h-full transition-all duration-500" 
                                style={{ width: `${((b.totalConstructionTime - b.remainingTurns) / b.totalConstructionTime) * 100}%` }}
                            />
                        </div>
                        <div className="text-[9px] text-gray-400">还需 {b.remainingTurns} 年</div>
                    </div>
                )}

                <div className="flex justify-between items-center">
                    <div className="flex items-center gap-2">
                        <span className="text-xl">{typeInfo.icon}</span>
                        <span className="font-bold text-yellow-100 text-xs">{typeInfo.name} <span className="text-[10px] text-yellow-800">Lv.{b.level}</span></span>
                    </div>
                    <button 
                        onClick={() => onAddBuilding(b.type)}
                        disabled={b.isConstructing || !req.met}
                        className={`px-2 py-0.5 text-[9px] rounded transition-all ${b.isConstructing ? 'bg-gray-800 text-gray-500' : 'bg-yellow-900/40 text-yellow-500 hover:bg-yellow-700 hover:text-white border border-yellow-900/30'}`}
                    >
                        {req.met ? '升级' : '限制'}
                    </button>
                </div>
                <p className="text-[10px] text-gray-500 leading-tight h-8 overflow-hidden">{typeInfo.desc}</p>
                <div className="mt-auto pt-2 border-t border-white/5 flex flex-col gap-1">
                    <span className="text-[9px] text-gray-500">派驻执事:</span>
                    <select 
                        className="bg-[#2c1810] text-[10px] text-yellow-500 border border-yellow-900/20 p-1 rounded outline-none"
                        value={b.assignedMemberId || ''}
                        onChange={(e) => onAssignBuilding(b.id, e.target.value || null)}
                    >
                        <option value="">- 空位 -</option>
                        {aliveMembers.map(m => (
                            <option key={m.id} value={m.id}>{m.name} ({m.realm})</option>
                        ))}
                    </select>
                </div>
            </div>
        );
    };

    const renderConstructionOption = (type: string, info: any) => {
        const building = state.buildings.find(b => b.type === type);
        if (building) return null;
        const req = checkRequirements(type, 1);
        const cost = info.baseCost;

        return (
            <div key={type} className="bg-[#2c1810]/40 p-3 rounded border border-yellow-900/10 group flex flex-col">
                <div className="flex justify-between items-center mb-1">
                    <span className="font-bold text-xs text-yellow-100">{info.icon} {info.name}</span>
                    <span className="text-[9px] text-yellow-600">✨ {cost}</span>
                </div>
                <p className="text-[9px] text-gray-500 mb-2 leading-relaxed">{info.desc}</p>

                <div className="mb-2 p-1 bg-black/20 rounded border border-white/5 space-y-0.5">
                    <div className={`text-[8px] ${state.members.some(m => REALM_ORDER.indexOf(m.realm) >= REALM_ORDER.indexOf(info.levels[0].reqRealm)) ? 'text-green-700' : 'text-red-900'}`}>
                        • 境界: {info.levels[0].reqRealm}
                    </div>
                    {info.levels[0].reqTalent && (
                        <div className={`text-[8px] ${state.members.some(m => (m.talents.百艺天赋 as any)[info.levels[0].reqTalent.type] >= info.levels[0].reqTalent.value) ? 'text-green-700' : 'text-red-900'}`}>
                            • {info.levels[0].reqTalent.type}: {info.levels[0].reqTalent.value}
                        </div>
                    )}
                </div>

                <button 
                    onClick={() => onAddBuilding(type)}
                    disabled={!req.met || state.spiritStones < cost}
                    className={`mt-auto w-full py-1 rounded text-[10px] font-bold transition-all ${req.met ? 'bg-yellow-900/20 hover:bg-yellow-700 text-yellow-500 hover:text-white border border-yellow-900/30' : 'bg-red-900/10 text-red-900 border border-red-900/20 cursor-not-allowed opacity-50'}`}
                >
                    {req.met ? '建造' : '条件不足'}
                </button>
            </div>
        );
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md p-4 font-serif overflow-hidden">
            <div className="relative w-full max-w-7xl h-[92vh] bg-[#1a1310] border-[10px] border-[#4a3728] rounded-sm shadow-2xl flex flex-col">
                {/* 侧边导航栏 */}
                <div className="flex h-full overflow-hidden">
                    <div className="w-48 bg-[#2c1810] border-r border-yellow-900/30 flex flex-col p-4 gap-2">
                        <h2 className="text-xl font-cursive text-yellow-500 mb-6 text-center border-b border-yellow-900/20 pb-4">望月李氏</h2>

                        <button onClick={() => setTab('overview')} className={`px-4 py-3 text-xs text-left rounded transition-all font-bold ${tab === 'overview' ? 'bg-yellow-900/40 text-yellow-400 border border-yellow-900/30 shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}>🏠 家族概况</button>
                        <button onClick={() => setTab('buildings')} className={`px-4 py-3 text-xs text-left rounded transition-all font-bold ${tab === 'buildings' ? 'bg-yellow-900/40 text-yellow-400 border border-yellow-900/30' : 'text-gray-500 hover:text-gray-300'}`}>🏗️ 营建布局</button>
                        <button onClick={() => setTab('positions')} className={`px-4 py-3 text-xs text-left rounded transition-all font-bold ${tab === 'positions' ? 'bg-yellow-900/40 text-yellow-400 border border-yellow-900/30' : 'text-gray-500 hover:text-gray-300'}`}>🎖️ 名分册封</button>

                        <div className="mt-6 pt-4 border-t border-yellow-900/10">
                            <p className="text-[9px] text-yellow-900 font-bold mb-3 uppercase tracking-widest">族产工坊</p>
                            {builtFunctionalBuildings.map(b => (
                                <button 
                                    key={b.id} 
                                    onClick={() => setTab((BUILDING_TYPES as any)[b.type].tab.toLowerCase() as any)} 
                                    className={`w-full px-4 py-3 text-xs text-left rounded transition-all font-bold mb-1 ${tab === (BUILDING_TYPES as any)[b.type].tab.toLowerCase() ? 'bg-blue-900/20 text-blue-400 border border-blue-900/30' : 'text-gray-600 hover:text-gray-400'}`}
                                >
                                    {(BUILDING_TYPES as any)[b.type].icon} {(BUILDING_TYPES as any)[b.type].name}
                                </button>
                            ))}
                        </div>
                    </div>

                    <div className="flex-1 flex flex-col overflow-hidden bg-black/20">
                        {/* 顶栏 */}
                        <div className="h-16 border-b border-yellow-900/20 flex items-center px-8 justify-between shrink-0">
                            <h3 className="text-yellow-500 font-cursive text-xl">
                                {tab === 'overview' && '家族宗谱 · 灵气分布'}
                                {tab === 'buildings' && '万丈高楼 · 营建所'}
                                {tab === 'positions' && '嫡庶有序 · 册封名号'}
                                {tab === 'alchemy' && '丹鼎之道 · 炼丹工坊'}
                            </h3>
                            <button onClick={onClose} className="w-10 h-10 bg-red-900/10 hover:bg-red-900/30 text-red-500 rounded-full flex items-center justify-center text-2xl transition-all">×</button>
                        </div>

                        {/* 内容区 */}
                        <div className="flex-1 overflow-hidden">
                            {tab === 'overview' && (
                                <div className="p-8 h-full overflow-y-auto custom-scrollbar">
                                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                                        {/* 家族名片 */}
                                        <div className="lg:col-span-1 bg-black/40 border border-yellow-900/20 p-6 rounded-xl space-y-6">
                                            <div className="text-center">
                                                <div className="w-24 h-24 bg-yellow-900/10 border-2 border-yellow-700/30 rounded-full mx-auto flex items-center justify-center mb-4">
                                                    <span className="text-4xl text-yellow-600 font-cursive">李</span>
                                                </div>
                                                <h4 className="text-2xl text-yellow-500 font-cursive">望月李氏</h4>
                                                <p className="text-[10px] text-gray-500 mt-1 uppercase tracking-[0.2em]">Wangyue Li Clan</p>
                                            </div>
                                            <div className="space-y-3">
                                                <div className="flex justify-between text-xs border-b border-white/5 pb-2">
                                                    <span className="text-gray-500">家族灵石</span>
                                                    <span className="text-yellow-400 font-bold">✨ {state.spiritStones}</span>
                                                </div>
                                                <div className="flex justify-between text-xs border-b border-white/5 pb-2">
                                                    <span className="text-gray-500">底蕴点数</span>
                                                    <span className="text-blue-400 font-bold">💎 {state.heritagePool}</span>
                                                </div>
                                                <div className="flex justify-between text-xs border-b border-white/5 pb-2">
                                                    <span className="text-gray-500">家族声望</span>
                                                    <span className="text-purple-400 font-bold">🎭 {state.merit}</span>
                                                </div>
                                            </div>
                                        </div>

                                        {/* 成员分布 */}
                                        <div className="lg:col-span-2 bg-black/40 border border-yellow-900/20 p-6 rounded-xl">
                                            <h4 className="text-yellow-600 font-bold text-sm border-b border-yellow-900/10 pb-3 mb-6">修为境界分布</h4>
                                            <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                                                {REALM_ORDER.filter(realm => realmDistribution[realm] > 0).map(realm => (
                                                    <div key={realm} className="bg-black/20 p-4 rounded border border-white/5 flex flex-col items-center">
                                                        <span className="text-gray-500 text-[10px] mb-1">{realm}</span>
                                                        <span className="text-2xl font-cursive text-yellow-200">{realmDistribution[realm]} <span className="text-[10px] font-sans">人</span></span>
                                                    </div>
                                                ))}
                                                {aliveMembers.length === 0 && (
                                                    <div className="col-span-full py-10 text-center text-gray-600 italic">暂无族人</div>
                                                )}
                                            </div>
                                            <div className="mt-8">
                                                <h4 className="text-yellow-600 font-bold text-sm border-b border-yellow-900/10 pb-3 mb-4">百艺大师</h4>
                                                <div className="flex flex-wrap gap-2">
                                                    {aliveMembers.filter(m => Object.values(m.talents.百艺天赋).some(v => v > 50)).map(m => (
                                                        <div key={m.id} className="bg-blue-900/10 border border-blue-900/20 px-3 py-1.5 rounded flex items-center gap-3">
                                                            <span className="text-xs font-bold text-blue-300">{m.name}</span>
                                                            <span className="text-[9px] text-gray-500">
                                                                {m.talents.百艺天赋.炼丹 > 50 && `炼丹 ${Math.floor(m.talents.百艺天赋.炼丹)}`}
                                                                {m.talents.百艺天赋.炼器 > 50 && ` 炼器 ${Math.floor(m.talents.百艺天赋.炼器)}`}
                                                            </span>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            )}

                            {tab === 'buildings' && (
                                <div className="flex h-full">
                                    <div className="flex-1 overflow-y-auto p-6 custom-scrollbar space-y-8 bg-black/10">
                                        <div>
                                            <h3 className="text-yellow-600 font-bold border-l-4 border-yellow-600 pl-3 mb-4 text-sm flex items-center gap-2">🌾 资源设施</h3>
                                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                                                {state.buildings.filter(b => (BUILDING_TYPES as any)[b.type].category === 'Resource').map(renderBuildingCard)}
                                            </div>
                                        </div>
                                        <div>
                                            <h3 className="text-blue-600 font-bold border-l-4 border-blue-600 pl-3 mb-4 text-sm flex items-center gap-2">⚙️ 功能设施</h3>
                                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                                                {state.buildings.filter(b => (BUILDING_TYPES as any)[b.type].category === 'Functional').map(renderBuildingCard)}
                                            </div>
                                        </div>
                                        <div>
                                            <h3 className="text-emerald-600 font-bold border-l-4 border-emerald-600 pl-3 mb-4 text-sm flex items-center gap-2">🏛️ 基础设施</h3>
                                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                                                {state.buildings.filter(b => (BUILDING_TYPES as any)[b.type].category === 'Base').map(renderBuildingCard)}
                                            </div>
                                        </div>
                                    </div>

                                    <div className="w-80 border-l border-yellow-900/20 bg-black/30 p-6 overflow-y-auto custom-scrollbar">
                                        <h3 className="text-yellow-700 font-bold border-b border-yellow-900/20 pb-2 mb-6 text-sm">建造面板</h3>
                                        <div className="space-y-4">
                                            {Object.entries(BUILDING_TYPES).map(([type, info]) => renderConstructionOption(type, info))}
                                        </div>
                                    </div>
                                </div>
                            )}

                            {tab === 'positions' && (
                                <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
                                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                                        {aliveMembers.map(m => (
                                            <div key={m.id} className="bg-black/30 border border-yellow-900/10 p-4 rounded-lg flex flex-col gap-3 shadow-inner">
                                                <div className="flex justify-between items-start">
                                                    <div className="flex flex-col">
                                                        <span className="text-sm font-bold text-yellow-100">{m.name}</span>
                                                        <span className="text-[10px] text-gray-500 font-sans">{m.realm}{m.subRealm}层</span>
                                                    </div>
                                                    <span className="text-[9px] bg-yellow-900/20 text-yellow-600 px-1.5 py-0.5 rounded border border-yellow-900/30 font-bold">{m.tier}</span>
                                                </div>
                                                <div className="space-y-1 mt-2">
                                                    <p className="text-[9px] text-gray-600">当前授职:</p>
                                                    <select className="bg-[#2c1810] text-[11px] text-orange-400 border border-yellow-900/20 p-2 rounded outline-none w-full font-bold" value={m.position} onChange={(e) => onUpdateMember(m.id, { position: e.target.value })}>
                                                        {POSITIONS.map(p => <option key={p} value={p}>{p}</option>)}
                                                    </select>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {tab === 'alchemy' && (
                                <div className="flex h-full overflow-hidden">
                                    {/* 炼丹室人员与进度 */}
                                    <div className="flex-1 p-8 overflow-y-auto custom-scrollbar bg-black/10">
                                        <div className="flex justify-between items-end mb-8">
                                            <div>
                                                <h4 className="text-yellow-600 font-bold mb-1">派驻炼丹师</h4>
                                                <div className="flex gap-4">
                                                    {state.buildings.filter(b => b.type === 'AlchemyRoom').map(b => {
                                                        const m = state.members.find(mem => mem.id === b.assignedMemberId);
                                                        return (
                                                            <div key={b.id} className="bg-black/40 border border-yellow-900/20 p-4 rounded-lg min-w-[200px]">
                                                                {m ? (
                                                                    <div className="flex items-center gap-3">
                                                                        <div className="w-10 h-10 bg-yellow-900/20 rounded-full flex items-center justify-center text-lg">👨‍🔬</div>
                                                                        <div>
                                                                            <p className="text-sm font-bold text-yellow-100">{m.name}</p>
                                                                            <p className="text-[10px] text-gray-500">炼丹造诣: {Math.floor(m.talents.百艺天赋.炼丹)}</p>
                                                                        </div>
                                                                    </div>
                                                                ) : (
                                                                    <p className="text-xs text-gray-700 italic">暂无派驻人员</p>
                                                                )}
                                                            </div>
                                                        );
                                                    })}
                                                </div>
                                            </div>
                                        </div>

                                        <h4 className="text-yellow-600 font-bold mb-4 border-b border-yellow-900/10 pb-2">可选丹方</h4>
                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                            {ALCHEMY_RECIPES.map(recipe => (
                                                <div key={recipe.pillId} className="bg-[#2c1810]/40 border border-yellow-900/10 p-4 rounded-lg flex flex-col gap-2">
                                                    <div className="flex justify-between items-center">
                                                        <span className="text-yellow-400 font-bold text-sm">💊 {recipe.name}</span>
                                                        <span className="text-[9px] text-gray-600">需求: {recipe.reqLevel}品</span>
                                                    </div>
                                                    <p className="text-[10px] text-gray-500 italic mb-2">{recipe.desc}</p>
                                                    <div className="flex flex-wrap gap-2">
                                                        {recipe.ingredients.map(ing => {
                                                            const invItem = state.inventory.find(i => i.id === ing.itemId);
                                                            const hasEnough = (invItem?.amount || 0) >= ing.amount;
                                                            return (
                                                                <span key={ing.itemId} className={`text-[9px] px-2 py-0.5 rounded border ${hasEnough ? 'border-green-900/30 text-green-700 bg-green-900/5' : 'border-red-900/30 text-red-900 bg-red-900/5'}`}>
                                                                    {invItem?.name || '未知'}: {ing.amount} (库: {invItem?.amount || 0})
                                                                </span>
                                                            );
                                                        })}
                                                    </div>
                                                    <button className="mt-4 w-full py-1.5 bg-yellow-900/20 text-yellow-600 border border-yellow-900/30 rounded text-[10px] font-bold hover:bg-yellow-700 hover:text-white transition-all">开炉炼制</button>
                                                </div>
                                            ))}
                                        </div>
                                    </div>

                                    {/* 右侧材料库 */}
                                    <div className="w-80 border-l border-yellow-900/20 bg-black/40 p-6 flex flex-col">
                                        <h4 className="text-yellow-700 font-bold text-sm border-b border-yellow-900/20 pb-2 mb-6">灵药仓库</h4>
                                        <div className="flex-1 overflow-y-auto custom-scrollbar space-y-2">
                                            {state.inventory.filter(i => i.type === 'Material').length > 0 ? (
                                                state.inventory.filter(i => i.type === 'Material').map(item => (
                                                    <div key={item.id} className="bg-black/30 border border-white/5 p-3 rounded flex justify-between items-center group">
                                                        <div>
                                                            <p className="text-xs font-bold text-gray-200">{item.name}</p>
                                                            <p className="text-[9px] text-gray-500 italic">{item.desc}</p>
                                                        </div>
                                                        <span className="text-yellow-600 font-mono text-sm">x{item.amount}</span>
                                                    </div>
                                                ))
                                            ) : (
                                                <p className="text-center py-20 text-gray-700 italic text-xs">尚无任何原材料</p>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                <div className="h-10 bg-black/60 border-t border-yellow-900/20 flex items-center px-8 text-[10px] text-gray-600 gap-8 shrink-0 tracking-widest">
                    <span>家族底蕴: <span className="text-blue-500">{state.heritagePool}</span></span>
                    <span>库存灵石: <span className="text-yellow-500">{state.spiritStones}</span></span>
                    <span>库存材料: <span className="text-green-600">{state.inventory.filter(i => i.type === 'Material').length} 种</span></span>
                </div>
            </div>
        </div>
    );
};

export default ClanManagement;
